window.$mobile_event = {}
window.$mobile_layer = {
  /**
   * 消息提示
   * @param message
   * @param type true：成功提示 false：失败提示 默认只显示文字
   */
  toast:(message,type)=>{
    if(type===undefined){
      return Toast(message)
    }else{
      return Toast[type?'success':'fail']({message: message});
    }
  },
  confirm:(opts,then,cancel)=>{
    opts = opts || {};
    Dialog.confirm({
        title: opts.title || "",
        message: opts.message || "",
        confirmButtonColor: "#317bc7"
      })
      .then(() => {
        if(typeof then==="function"){
          then();
        }
      })
      .catch(() => {
        if(typeof cancel==="function"){
          cancel();
        }
      })
  },
  /**
   * 全层loading，默认loading不会清除
   * @param msg 提示消息
   * @param maskClick=1:禁用背景点击
   */
  loading:(msg,maskClick)=>{
    return Toast.loading({
      duration: 0,       // 持续展示 toast
      forbidClick: maskClick===1, // 禁用背景点击
      message: msg||'请等待...'
    })
  },
  //清除所有弹窗，默认当前只会显示一个，在当前弹窗未清除时调用另一个弹窗会强制覆盖
  clear:(id)=>{
    Toast.clear(id);
  }
}
