<template>
  <van-cell-group :title="showIconInfo?'':label">
    <van-cell v-if="showIconInfo" class="icon-cell">
      <div class="van-cell-group__title" slot="title"><IconInline :label="label" :txt="attributes.basis.dataCapion" :audio="attributes.basis.dataAudioUrl" :video="attributes.basis.dataVideoUrl"></IconInline></div>
    </van-cell>
    <van-cell :class="{'van-cell--required':attributes.basis.required}" title="开始日期" is-link arrow-direction="down" :value="!this.attributes.value.sdate?'':(new Date(this.attributes.value.sdate)).Format('yyyy年MM月dd日')" @click="showBegin=true" />
    <van-popup v-model="showBegin" @closed="onBeginCancel" position="bottom">
      <van-datetime-picker
          v-model="beginDate"
          type="date"
          title="开始日期"
          :min-date="minDate"
          :max-date="endDate"
          :show-toolbar="true"
          :formatter="formatter"
          @cancel="onBeginCancel"
          @confirm="onBeginConfirm"
      />
    </van-popup>
    <van-cell :class="{'van-cell--required':attributes.basis.required}" title="结束日期" is-link arrow-direction="down" :value="!this.attributes.value.edate?'':(new Date(this.attributes.value.edate)).Format('yyyy年MM月dd日')" @click="showEnd=true" />
    <van-popup v-model="showEnd" @closed="onEndCancel" position="bottom">
      <van-datetime-picker
          v-model="endDate"
          type="date"
          title="结束日期"
          :min-date="beginDate"
          :max-date="maxDate"
          :show-toolbar="true"
          :formatter="formatter"
          @cancel="onEndCancel"
          @confirm="onEndConfirm"
      />
    </van-popup>
  </van-cell-group>
</template>

<script>
  import base from '../../lib/base'

  export default {
    name: "DateIntervalPicker",
    extends:base,
    data() {
      return {
        showBegin:false,
        showEnd:false,
        beginDate:null,
        endDate:null,
      }
    },
    computed:{
      minDate:function () {
        return new Date(this.beginDate.getFullYear()-20+'')
      },
      maxDate:function () {
        return new Date(this.endDate.getFullYear()+20+'')
      }
    },
    created: function () {
      this.attributes.value={};
      if(this.attributes['basis']['defaultValue']){
        if(this.attributes['basis']['defaultValue']['sdate']){
          this.beginDate=new Date(this.attributes['basis']['defaultValue']['sdate'].replace(/-/g,'/'));
          this.attributes.value.sdate=(this.beginDate).Format('yyyy/MM/dd');
        }
        if(this.attributes['basis']['defaultValue']['edate']){
          this.endDate=new Date(this.attributes['basis']['defaultValue']['edate'].replace(/-/g,'/'));
          this.attributes.value.edate=(this.endDate).Format('yyyy/MM/dd');
        }
        if(this.beginDate&&!this.endDate){
          this.endDate=this.beginDate;
        }
        if(!this.beginDate&&this.endDate){
          this.beginDate=new Date(this.endDate.getFullYear()-20+'');
        }
      }else{
        this.beginDate=new Date();
        this.endDate=new Date(new Date().getFullYear()+20+'');
      }
      //错误提示检测
      this.checkFinish();
    },
    methods: {
      onBeginConfirm(date) {
        this.beginDate=date;
        this.$set(this.attributes.value,'sdate',(date).Format("yyyy/MM/dd"));
        this.showBegin=false;
        if(!this.attributes.value.edate){
          this.endDate=new Date(date.getFullYear()+10+'');
        }
        this.checkFinish();
        this.emitParent(this.attributes.value);
      },
      onBeginCancel() {
        this.attributes.value.sdate&&(this.beginDate=new Date(this.attributes.value.sdate.replace(/-/g,'/')));
        this.showBegin=false
      },
      onEndConfirm(date) {
        this.endDate=date;
        this.$set(this.attributes.value,'edate',(date).Format("yyyy/MM/dd"));
        this.showEnd=false;
        if(!this.attributes.value.sdate){
          this.beginDate=new Date(date.getFullYear()-20+'');
        }
        this.checkFinish();
        this.emitParent(this.attributes.value);
      },
      onEndCancel() {
        this.attributes.value.edate&&(this.endDate=new Date(this.attributes.value.edate.replace(/-/g,'/')));
        this.showEnd=false
      },
      checkFinish(){
        this.attributes.error=true;
        if(!this.attributes['basis']['validate']['required']){
          this.attributes.error=false;
        }else if(!!this.attributes['value']['sdate']&&!!this.attributes['value']['edate']) {
          this.attributes.error=false;
        }else{
          this.attributes.errorMsg = `请选择${this.attributes.basis.label}`;
        }
      },
      formatter(type, value) {
        if (type === 'year') {
          return `${value}年`;
        } else if (type === 'month') {
          return `${value}月`
        }else if (type === 'day') {
          return `${value}日`
        }
        return value;
      }
    },
    components: {}
  }
</script>
