<template>
  <Load v-if="currentData.length===0"></Load>
  <div v-else :class="['van-second-box',{'no-padding-bottom':showMarker}]">
    <div ref="top"></div>
    <!--  只读遮罩层  -->
    <div v-if="showMarker" class="readonly-box"></div>
    <!--  滑动定位(小程序不要)  -->
    <div
        class="fixed-div"
        draggable="true"
        ref="default_drag_comp"
        @touchstart="down"
        @touchmove="move"
        @touchend="end"
    >
      <div @click="arrow" :class="['page-arrow',{'page-arrow-up':showArrow},{'drag':flags===1}]">
        <van-icon name="arrow-down"/>
      </div>
      <div :class="['van-fixed-box',{'fixed-box-show':showArrow}]"
           :style="{height:showArrow?(47*navPosition.length+'px'):0}">
        <div class="go" v-for='(item,index) in navPosition' :key="index" @click="go(item)">
          {{!item.tab?item.name:item.tab.alias?item.tab.alias:item.tab.name?item.tab.name:item.tab.number}}
        </div>
      </div>
    </div>
    <!--  自定义特殊显示  -->
    <div class="van-kc-box" v-if="showDesc">
      <p class="kc">{{desc.kc}}</p>
      <div class="kc-info-box">
        <div>
          <van-icon name="manager-o"/>
          <span>{{desc.teacher}}</span>
        </div>
        <div>
          <van-icon name="clock-o"/>
          <span>{{desc.time}}</span>
        </div>
      </div>
    </div>

    <!--  审核 --start-- -->
    <div
        v-if="auditInfo"
        @click="review=(showMarker?false:true)"
        draggable="true"
        @touchstart="down"
        @touchmove="move"
        @touchend="end"
        ref="default_drag_comp2"
        :class="['review-point',{'show-review-point':(auditInfo.result.num1>0||auditInfo.result.num0>0)&&!review},{'drag':flags===2}]"
    >审
    </div>
    <!--  审核结果集-->
    <van-popup
        class="van-review-popup"
        v-model="review"
        position="bottom"
        :overlay="false"
        :lock-scroll="false"
    >
      <div v-if="auditInfo" class="review-box">
        <p class="review-title">
          审核错误
          <van-icon class="review-close" @click="review=false" name="close"/>
        </p>
        <div class="review-main">
          <ReView
              v-for="(item,index) in auditInfo.result.detail"
              :key="index"
              :info="item"
          ></ReView>
        </div>
      </div>
    </van-popup>
    <!--  审核 --end-- -->

    <!--  表单项  -->
    <template v-for="(item,index) in currentData">
      <!-- 子表 -->
      <div
          :key="index"
          :data-index="index"
          :id="item['basis']['id']"
          class="van-tab-box"
          v-if="item['basis']['ctrl_type']==='SubTableVertical'"
      >
        <h2 class="van-h2" v-if="item.basis.label">{{item.basis.label}}</h2>
        <div
            :class="['van-tab-container',{'van-tab-w130':item['basis']['buttons'].length>0}]"
        >
          <div class="van-tab-button-box">
            <div
                v-for="btn in item['basis']['buttons']"
                :class="['van-tab-btn',{'add':btn['actionName'].includes('addnew')}]"
                @click="tabClick(btn['actionName'],index)"
            >
              <van-icon v-if="btn['actionName'].includes('addnew')" name="add-o"/>
              {{btn['text']}}
            </div>
            <div @click="tabClick('delete',index)" class="van-tab-btn del">
              <van-icon name="close"/>
              删除
            </div>
            <!--          <div @click="tabClick('clear',index)" class="van-tab-btn del">-->
            <!--            <van-icon name="delete"/>-->
            <!--            清空-->
            <!--          </div>-->
          </div>
          <van-tabs
              swipeable
              color="#317bc7"
              :line-height="0"
              :lazy-render="false"
              v-model="item['active']"
              :swipe-threshold="2"
          >
            <template v-for="(child,childNum) in item['items']">
              <van-tab :id="item['element'][childNum]['eleId']">
                <div class="van-tab-title" slot="title">
                  <p class="van-ellipsis">{{item['element'][childNum]['name']||''}}</p>
                  <p>
                    {{childTabMode===1?(item['element'][childNum]['alias']||childNum+1):(item['element'][childNum]['alias']
                    || item['element'][childNum]['number'])+''}}</p>
                </div>
                <FormItem
                    v-for="(childItem,childIndex) in child"
                    :data-index="childIndex"
                    :key="childIndex"
                    :formObj="childItem"
                    :eleId="item['element'][childNum]['eleId']"
                ></FormItem>
              </van-tab>
            </template>
          </van-tabs>
        </div>
      </div>
      <!-- 主表 -->
      <div class="myBox" v-else :key="index" :ref="item.basis.id">
        <FormItem :data-index="index" :formObj="item" @btnClick="btnClick"></FormItem>
      </div>
    </template>

    <!--<div class="btn-box">-->
    <!--<van-button size="large" type="danger" :loading="loading" @click="next">{{btnTxt}}</van-button>-->
    <!--</div>-->
    <!--    数字键盘-->
    <!--    <van-number-keyboard-->
    <!--        :show="$store.state.numberKeyboard"-->
    <!--        :z-index="110"-->
    <!--        theme="custom"-->
    <!--        extra-key="."-->
    <!--        close-button-text="完成"-->
    <!--        @blur="$store.state.numberKeyboard = false"-->
    <!--        @input="onNumberInput"-->
    <!--        @delete="onNumberDelete"-->
    <!--    />-->

    <van-dialog
        className="icon-info-dialog"
        v-model="$store.state.showDialogInfo"
        :show-confirm-button="false"
        closeOnClickOverlay
        :beforeClose="infoDialogClose"
    >
      <div>
        <div v-if="$store.state.dialogInfoType==='txt'" class="txt">{{$store.state.dialogInfoSource}}</div>
        <video v-else-if="$store.state.dialogInfoType==='video'" id="icon-video" controls autoplay loop
               :src="$store.state.dialogInfoSource"></video>
        <audio v-else id="icon-audio" controls autoplay loop :src="$store.state.dialogInfoSource"></audio>
      </div>
    </van-dialog>
    <div ref="bottom"></div>
  </div>
</template>

<script>
  import form from "../../lib/form";
  import dom from "../../lib/domData";
  import FormItem from "@/components/bhc/FormItem";
  import ReView from "@/components/bhc/ReView";

  export default {
    name: "FormIndex",
    extends: form,
    mixins: [dom],
    components: {FormItem, ReView},
    data() {
      return {
        showMarker: false, //全屏遮罩层
        review: false, //审核结果显示
        auditInfo: null, //审核结果
        showDesc: false, //特殊信息显示
        showArrow: false, //显示展开
        childTabMode: 0,//子表tab索引模式,1为顺序索引
        //可用表单组件类型
        forms: [
          "RadioBox",
          "Select",
          "CheckBox",
          "Datepicker",
          "TimePicker",
          "DateIntervalPicker",
          "TextBox",
          "TextArea",
          "DataChoice",
          "AutoComplete"
        ],
        //可用组件类型
        ctrls: [
          "RadioBox",
          "Rank",
          "Select",
          "CheckBox",
          "Datepicker",
          "TimePicker",
          "DateIntervalPicker",
          "TextBox",
          "TextArea",
          "Title3",
          "Title4",
          "Title5",
          "Title6",
          "DataChoice",
          "Label",
          "ButtonBar",
          "AutoComplete",
          "NavPosition"
        ],
        desc: {
          kc: "",
          time: "",
          teacher: ""
        },
        flags: false,
        position: {x: 0, y: 0},
        nx: "",
        ny: "",
        dx: "",
        dy: "",
        navPosition: [
          {ref: "top", name: "页头"},
          {ref: "bottom", name: "页尾"}
        ],
        hasPosition: false,
        subTabNumber: 0
      };
    },
    created() {
      //页面是否只能浏览
      let _this = this;
      if (this.$route.query.readonly) {
        // 只读
        this.showMarker = true;
      }
      //tab索引排序模式
      window.$mobile_data.childTabMode == 1 && (this.childTabMode = 1);
      //判断是否需要触发domReady事件
      window.$mobile_data.renderJustOnce = 1;
      //通过ele元素查找下一个Dom节点
      window.getNextSibilingsNode = function (ele) {
        var parsent = ele.parentNode; //获取元素父元素
        var _allC = parsent.childNodes;
        var childrens = []; //获取兄弟元素
        for (let j = 0; j < _allC.length; j++) {
          if (
              !new RegExp(" " + "hide-item" + " ").test(
                  " " + _allC[j].className + " "
              )
          ) {
            childrens.push(_allC[j]);
          }
        }
        var i = 0;
        for (i; i < childrens.length; i++) {
          if (childrens[i].nodeType == 1 && childrens[i] == ele) {
            //元素节点nodeType值为1，剔除文本节点
            if (childrens[i + 1] && childrens[i + 1].nodeType == 1) {
              //防止li之间没有换行，直接选择下一个i+1
              return childrens[i + 1];
            } else if (
                childrens[i + 2] &&
                childrens[i + 2].nodeType == 1
            ) {
              //跳过文本节点，所以i+2
              return childrens[i + 2];
            } else {
              return false;
            }
          }
        }
      };
      //通过ele元素找寻第一个class为className的父级
      window.findClassParent = function (ele, className) {
        let parent = ele.parentElement;
        if (!parent) {
          return false;
        } else if (
            parent.className.includes(className) &&
            !parent.className.includes("hide-item")
        ) {
          return parent;
        } else {
          return window.findClassParent(parent, className);
        }
      };
      //切换按钮隐藏只读的方法
      window.$mobile_event.readonly = function (type) {
        type = type === 1 ? true : false;
        if (type) {
          _this.showMarker = true;
          document.querySelector(
              ".van-fixed-btn-box"
          ).style.display = "none";
        } else {
          _this.showMarker = false;
          document.querySelector(
              ".van-fixed-btn-box"
          ).style.display = "block";
        }
      };
      //文本框回车聚焦
      document.addEventListener("keydown", function (e) {
        if (
            e.keyCode === 13 &&
            window.$mobile_page.nextInputParent &&
            window.$mobile_page.nextInput
        ) {
          let next = window.$mobile_page.nextInputParent,
              input = window.$mobile_page.nextInput;
          window.$mobile_page.nextInputParent = null;
          window.$mobile_page.nextInput = null;
          next.scrollIntoView();
          input.focus();
          next = null;
          input = null;
        }
      });
      //页面尺寸变化
      window.$mobile_page.windowHeightChange = function (parentHeight, iframeHeight) {
        console.info('parentHeight And iframeHeight：', parentHeight, iframeHeight)
      };

      //暴露到全局
      window.tabClick = this.tabClick;
      window.$mobile_page.useIndex = this.useIndex;
      //隐藏请求消息显示
      window.$mobile_page.hideResMsg = false;
    },
    updated() {
      window.$mobile_data.renderJustOnce === 1 && this.$nextTick(function () {
        window.$mobile_data.renderJustOnce = 2;
        typeof window.domReady === "function" && window.domReady();
      });
    },
    methods: {
      initDomData(dom, dataSource) {
        //小程序显示简介控制
        let head = this.nameSpace.replace(/\./g, "_");

        // --红网小程序的课程评价--start
        if (this.$store.state.subForm[head + ".kc"]) {
          this.desc.kc = this.$store.state.subForm[head + ".kc"]["text"];
          this.desc.time = this.$store.state.subForm[head + ".sksj"]["sdate"].slice(5, 16);
          this.desc.teacher =
              this.$store.state.subForm[head + ".skls"] &&
              this.$store.state.subForm[head + ".skls"]["text"]
                  ? this.$store.state.subForm[head + ".skls"]["text"]
                  : "暂无";
          this.showDesc = true;
        }
        // --红网小程序的课程评价--end

        console.info("节点数据：", dom);
        // console.info('源数据：', dataSource);
        // console.info('表单数据：', this.$store.state.subForm);

        let pageArr = []; //每一页暂存数据
        this.$store.commit("initForms"); //清空题库

        //判断类型，是否是题目
        let pageIndex = 0; //pageCurrentData中的索引
        for (let i = 0, length = dom.length; i < length; i++) {
          //判断是否为子表，字表需要提取数据，否则判断是否是可用组件或逻辑审核
          if (dom[i]["ctrl_type"] === "SubTableVertical") {
            window.SubTableVertical = dom[i]["metadata_fullcode"];
            let subChild = {
              basis: {
                id: dom[i]["metadata_fullcode"],
                $caption: dom[i]["$caption"],
                ctrl_type: "SubTableVertical",
                label: dom[i]["$label"],
                buttons: dom[i]["$buttonBar"]["buttons"]
              },
              items: [[]],
              element: [], //每个子tab的id,num存放
              number: [], //当新增子表时优先从这里shift,删除子表时push当前删除的num
              delete: [], //删除的子表
              active: 0 //激活索引
            };
            Object.freeze(subChild.basis);
            //循环两次是因为数据可能是一个子表但是嵌套了多层
            for (let n = 0, subLength = dom[i]["$templates"].length; n < subLength; n++) {
              //合并显示的子表项标题（遍历templates拼接方式）
              // let label = "";
              // for (let l = 0, colLength = dom[i]['$templates'][n]['columns'].length; l < colLength; l++) {
              //   //对最后一项添加（）
              //   let str = "";
              //   if (l === colLength - 1) {
              //     str = `(${dom[i]['$templates'][n]['columns'][l]['text']})`;
              //   } else {
              //     str = dom[i]['$templates'][n]['columns'][l]['text'];
              //   }
              //   label += str;
              // }
              for (let m = 0, childLength = dom[i]["$templates"][n]["template"]["control"]["children"].length;
                  m < childLength;
                  m++
              ) {
                //自定义子表项标题（拼接自身label与templates最后一位）
                let label = "";
                if (dom[i]["$templates"][n]["template"]["control"]["children"][m]["ctrl_type"] === "Label") {
                  label = dom[i]["$templates"][n]["columns"][0]
                      ? dom[i]["$templates"][n]["columns"][0][
                      "text"
                      ] || ""
                      : "";
                } else {
                  // label = (dom[i]['$templates'][n]['columns'][dom[i]['$templates'][n]['columns'].length - 1]['text'] + ' ' + dom[i]['$templates'][n]['template']['control']['children'][m]['$label'] || '').replace(/--|——|—|-/gi, '');
                  label = (
                      dom[i]["$templates"][n]["template"][
                          "control"
                          ]["children"][m]["$label"] || ""
                  ).replace(/--|——|—|-/gi, "");
                }
                //将已保存的数据增加标识_id,否则初始化为单数组
                if (
                    this.$store.state.subForm[
                        dom[i]["metadata_fullcode"]
                        ] != null &&
                    this.$store.state.subForm[
                        dom[i]["metadata_fullcode"]
                        ] != undefined &&
                    this.$store.state.subForm[
                        dom[i]["metadata_fullcode"]
                        ].length > 0
                ) {
                  for (
                      let itemNum = 0,
                          itemLength = this.$store.state.subForm[
                              dom[i]["metadata_fullcode"]
                              ].length;
                      itemNum < itemLength;
                      itemNum++
                  ) {
                    let objItem = this.doingData(
                        dom[i]["$templates"][n]["template"][
                            "control"
                            ]["children"][m],
                        dataSource,
                        pageIndex,
                        dom[i]["metadata_fullcode"],
                        itemNum,
                        label
                    );
                    if (objItem) {
                      if (
                          objItem["basis"]["ctrl_type"] !=
                          "Label"
                      ) {
                        objItem[
                            "_id"
                            ] = this.$store.state.subForm[
                            dom[i]["metadata_fullcode"]
                            ][itemNum]["_id"];
                      }
                      if (
                          subChild["items"][
                              itemNum
                              ] instanceof Array
                      ) {
                        subChild["items"][itemNum].push(
                            objItem
                        );
                      } else {
                        subChild["items"][itemNum] = [
                          objItem
                        ];
                      }
                    } else {
                    }
                  }
                } else {
                  let objItem = this.doingData(
                      dom[i]["$templates"][n]["template"][
                          "control"
                          ]["children"][m],
                      dataSource,
                      pageIndex,
                      dom[i]["metadata_fullcode"],
                      -1,
                      label
                  );
                  objItem && subChild["items"][0].push(objItem);
                }
              }
            }
            //增加子表唯一id
            let store = this.$store.state.subForm[subChild["basis"]["id"]] || null;
            for (let eleIndex = 0, eleLength = subChild["items"].length; eleIndex < eleLength; eleIndex++) {
              //序号
              let number = (store && store[eleIndex] && (store[eleIndex][subChild["basis"]["id"] + ".ds_order"]) != null
                  && !isNaN(store[eleIndex][subChild["basis"]["id"] + ".ds_order"]))
                  ? store[eleIndex][subChild["basis"]["id"] + ".ds_order"]
                  : subChild["element"].length + 1;
              //判断是否缺失了序号
              if (subChild["element"].length >= 1 &&
                  subChild["element"][subChild["element"].length - 1]["number"] * 1 + 1 < number) {
                for (var diff = subChild["element"][subChild["element"].length - 1]["number"] * 1 + 1;
                     diff < number;
                     diff++
                ) {
                  subChild["number"].indexOf(diff) === -1 &&
                  subChild["number"].push(diff);
                }
                //跳过当前最后一项
                subChild["number"].push(diff * 1 + 1);
              }
              subChild["element"].push({
                eleId: this.guid(),//便于二次开发查找，对应tab
                number: number,
                name: "",
                alias: ""
              });
            }
            pageArr.push(subChild);
            window.$mobile_ctrl[window.SubTableVertical] = subChild;
            //添加tab
            if (window.$mobile_page.useIndexPos) {
              this.useIndex();
            }
            pageIndex++;
          } else if (this.ctrls.indexOf(dom[i]["ctrl_type"]) > -1 || dom[i]["ctrl_type"] === "ButtonBar") {
            let objItem = this.doingData(dom[i], dataSource, pageIndex);
            if (objItem) {
              pageArr.push(objItem);
              pageIndex++;
            }
          } else if (dom[i]["ctrl_type"] === "AuditInfo") {
            this.auditInfo = {
              id: dom[i]["metadata_fullcode"],
              result: dom[i]["$value"],
              isSyncChildList: dom[i]["$isSyncChildList"] //是否需要将审核结果同步到每一个小子表
            };
            if (this.$store.state.subForm[dom[i]["metadata_fullcode"]]) {
              this.auditInfo.result = this.$store.state.subForm[
                  dom[i]["metadata_fullcode"]
                  ];
            }
            if (typeof this.auditInfo.result.detail === "string") {
              this.auditInfo.result.detail = JSON.parse(
                  this.auditInfo.result.detail || "[]"
              );
            }
            //数据出现错误，初始化审核结果
            if (Object.prototype.toString.call(this.auditInfo.result.detail) !== "[object Array]") {
              this.auditInfo.result = {
                detail: [], //审核错误结果集合
                num0: 0, //提示性审核数量，可填写备注
                num1: 0, //必要性审核数量,只要>0，审核不通过
                state: 1 //审核结果，1为通过，-1不通过
              };
            }
          }
          //判断题目集合是否分页
          // if ((i + 1) % 4 === 0 || i + 1 === length) {
          //   //推入题库并重置暂存数组
          //   this.$store.commit("addForms", pageArr);
          //   pageArr = [];
          // }
        }

        //启用分页，屏蔽此处commit
        this.$store.commit("addForms", pageArr);
        //初始化当前页

        this.currentData = this.$store.state.forms[0];
        //暴露到全局
        window.pageCurrentData = this.currentData;
        if (this.$store.state.forms.length === 1) {
          // this.btnTxt = '提交问卷';
          this.isLast = true;
        }
      },
      useIndex(subChild) {
        if (!subChild) {
          for (let i = 0, length = window.pageCurrentData.length; i < length; i++) {
            if (pageCurrentData[i]["basis"]["ctrl_type"] === "SubTableVertical") {
              subChild = pageCurrentData[i];
              break;
            }
          }
        }
        if (window.$mobile_page.useIndexPos) {
          for (let nav = 0, navLength = subChild.element.length; nav < navLength; nav++) {
            this.navChange({
              tabId: subChild['basis']['id'],
              data: subChild,
              tab: subChild.element[nav]
            });
          }
        } else {
          for (let nav = 0; nav < this.navPosition.length; nav++) {
            if (this.navPosition[nav]['tab']) {
              this.navPosition.splice(nav, 1);
              nav--;
            }
          }
        }
      },
      //子表按钮点击事件
      tabClick(type, index) {
        //判断页面是否只读
        if (this.$route.query.readonly == 1) {
          return false
        }
        if (!this.subTabNumber) {
          this.subTabNumber =
              this.currentData[index]["element"][
              this.currentData[index]["element"].length - 1
                  ]["number"] * 1;
        }
        if (type.includes("addnew")) {
          if (this.currentData[index]["items"].length > 20) {
            this.$toast({
              message: "最多添加二十条记录",
              duration: 1500
            });
            return;
          }
          // 复制第一个表的组件
          let copy = JSON.parse(
              JSON.stringify(this.currentData[index]["items"][0])
          );
          //清空_id、已填写的答案、初始赋值，对Label进行特殊赋值处理
          for (let i = 0, length = copy.length; i < length; i++) {
            delete copy[i]["_id"];
            copy[i]["error"] = false;
            copy[i]["exclude"] = false;
            let copyType = copy[i]["basis"]["ctrl_type"];
            if (copyType.includes("CheckBox")) {
              copy[i]["basis"]["defaultValue"] = [];
              copy[i]["value"] = [];
            } else {
              copy[i]["basis"]["defaultValue"] = "";
              copyType !== "Label" && (copy[i]["value"] = "");
            }
          }
          let number = null;
          if (this.currentData[index]["number"].length > 0) {
            number = this.currentData[index]["number"].shift();
          } else {
            number = this.subTabNumber * 1 + 1;
            this.subTabNumber = number;
          }
          let eleId = this.guid(), newTab = {
            eleId: eleId,
            name: "",
            number: number,
            alias: ""
          };
          this.currentData[index]["element"].push(newTab);
          this.currentData[index]["items"].push(copy);
          typeof window.addSubChild === "function" &&
          window.addSubChild(eleId, this.currentData[index]["element"]);
          this.$nextTick(() => {
            this.currentData[index]["active"] =
                this.currentData[index]["items"].length - 1;
            typeof window.afterAddTabRender === "function" &&
            window.afterAddTabRender(eleId);
          });
          //增加定位索引
          if (window.$mobile_page.useIndexPos) {
            this.navChange({
              tabId: this.currentData[index]['basis']['id'],
              data: this.currentData[index],
              tab: newTab
            });
          }
        } else if (type.includes("delete")) {
          if (this.currentData[index]["items"].length === 1) {
            this.$toast({
              message: "不允许删除最后一列",
              duration: 1500
            });
          } else {
            this.$dialog
                .confirm({
                  title: "",
                  message: "确定要删除此人信息吗？",
                  confirmButtonColor: "#317bc7"
                })
                .then(() => {
                  // on confirm
                  //将审核结果中含有此索引的错误全部清除
                  for (
                      let i = 0;
                      i < this.auditInfo.result.detail.length;
                      i++
                  ) {
                    //比对审核结果中，错误索引>删除索引，-1
                    if (
                        this.auditInfo.result.detail[i]["index"] >
                        this.currentData[index]["active"]
                    ) {
                      this.auditInfo.result.detail[i]["index"]--;
                    } else if (
                        this.auditInfo.result.detail[i]["index"] ==
                        this.currentData[index]["active"]
                    ) {
                      let delAudit = this.auditInfo.result.detail.splice(
                          i,
                          1
                      );
                      delAudit[0]["level"] == 1
                          ? this.auditInfo.result["num1"]--
                          : this.auditInfo.result["num0"]--;
                      i--;
                    }
                    // this.currentData[index]['active']
                  }

                  let del = this.currentData[index]["items"].splice(
                      this.currentData[index]["active"],
                      1
                  );
                  let ele = this.currentData[index]["element"].splice(
                      this.currentData[index]["active"],
                      1
                  );
                  //tab索引模式
                  if (this.childTabMode != 1) {
                    //将删除的number按从小到大插入存放数组,首先判断是否满足直接push的条件，1是空数组，2是大于最后一个数。
                    let length = this.currentData[index]["number"]
                        .length;
                    if (
                        length === 0 ||
                        ele[0]["number"] >
                        this.currentData[index]["number"][
                        length - 1
                            ]
                    ) {
                      //因为这是一个从小到大排序的数组，所以比最后一个大就可以在数组后加入数值
                      this.currentData[index]["number"].push(
                          ele[0]["number"]
                      );
                    } else {
                      for (let i = 0; i < length; i++) {
                        if (
                            ele[0]["number"] <
                            this.currentData[index]["number"][i]
                        ) {
                          this.currentData[index][
                              "number"
                              ].splice(i, 0, ele[0]["number"]); //在第i个地方插入个数m
                          break; //打断循环
                        }
                      }
                    }
                  }
                  //对于已经存在数据增加删除标识
                  if (del[0][0]["_id"]) {
                    //设置已改动
                    this.compareResult = true;
                    let did = (
                        this.currentData[index]["basis"]["id"] +
                        ".DS_DELETED"
                    ).toLowerCase();
                    //操作id赋值
                    let obj = {_id: del[0][0]["_id"]};
                    obj[did] = 1;
                    obj[
                    this.currentData[index]["basis"]["id"] +
                    "." +
                    this.currentData[index]["basis"]["id"] +
                    "_id"
                        ] = del[0][0]["_id"];
                    this.currentData[index]["delete"].push(
                        Object.freeze(obj)
                    );
                  } else {
                  }
                  //处理定位
                  if (window.$mobile_page.useIndexPos) {
                    for (let nav = 0, navLength = this.navPosition.length; nav < navLength; nav++) {
                      if (this.navPosition[nav]['tab'] && this.navPosition[nav]['tab']['eleId'] === ele[0]['eleId']) {
                        this.navPosition.splice(nav, 1);
                        break;
                      }
                    }
                  }
                  //删除后跳转到前一个
                  let active = --this.currentData[index]["active"];
                  this.$nextTick(() => {
                    this.currentData[index]["active"] = active;
                    typeof window.removeSubChild === "function" &&
                    window.removeSubChild(ele[0].eleId, this.currentData[index]["active"], this.currentData[index]["element"]);
                  });
                })
                .catch(() => {
                  // on cancel
                });
          }
        } else if (type.includes("clear")) {
          this.$dialog
              .confirm({
                title: "",
                message: "确定要清空所有子表吗？",
                confirmButtonColor: "#317bc7"
              })
              .then(() => {
                // on confirm
                let del = this.currentData[index]["items"].splice(1);
                for (let i = 0, length = del.length; i < length; i++) {
                  let id = del[i][0]["_id"];
                  if (id) {
                    this.currentData[index]["delete"][i] = {
                      _id: id
                    };
                    let did = (
                        this.currentData[index]["basis"]["id"] +
                        ".DS_DELETED"
                    ).toLowerCase();
                    //操作id赋值
                    this.currentData[index]["delete"][i][did] = 1;
                    this.currentData[index]["delete"][i][
                    this.currentData[index]["id"] +
                    "." +
                    this.currentData[index]["id"] +
                    "_id"
                        ] = id;
                  }
                }
              })
              .catch(() => {
                // on cancel
              });
        }
      },
      /**
       * 表单类型数据处理
       * @param domItem 表单项
       * @param dataSource 数据源
       * @param index 当前索引序号
       * @param pid 父级id（子表）
       * @param pIndex 所在父级索引
       * @param label 显示字符
       * @returns {{visible: *, id: *, label: (*|string), ctrl_type: *, value: (*|string)}|boolean}
       */
      doingData(domItem, dataSource, index, pid, pIndex, label) {
        if (this.ctrls.indexOf(domItem["ctrl_type"]) === -1) {
          return false;
        }
        //暂存数据对象,共有属性
        let obj = {
          value: domItem["$value"] || "",
          exclude: false, //提交答案时是否排除此选项
          basis: JSON.parse(JSON.stringify(domItem))
        };
        obj.basis["id"] = domItem["metadata_fullcode"];
        obj.basis["num"] = index;
        obj.basis["visible"] = domItem["$visible"]; //是否隐藏
        obj.basis["label"] = domItem["$label"] || "";
        obj.basis["requireRemark"] = domItem["$requireRemark"] || false; //提示性审核是否必须填写备注

        delete obj.basis["index"];

        //私有属性初始化
        // 时间的格式
        if (domItem.$timeFormat) {
          obj.basis.timeFormat = domItem.$timeFormat;
        }
        // 时间的格式2
        if (domItem.$chooseType) {
          obj.basis.chooseType = domItem.$chooseType;
        }
        //是否是子表中的表单，记录父级id，初始化主栏显示文本
        if (pid) {
          obj["basis"]["pid"] = pid;
          obj["basis"]["label"] = label;
        }
        //按钮组
        if (domItem["$buttonBar"]) {
          delete obj.index;
          obj["buttons"] = domItem["$buttonBar"]["buttons"];
          //只用作显示相关,取消vue劫持
          Object.freeze(obj);
        } else if (domItem["ctrl_type"] === "Rank") {
          //评分
          obj["styleType"] = domItem["styleType"];
          obj["chooseType"] = domItem["chooseType"];
          obj["rowSet"] = domItem["rowSet"];
          obj["basis"]["defaultValue"] =
              this.$store.state.subForm[domItem["metadata_fullcode"]] ||
              null;
          index++;
        } else if (domItem["ctrl_type"].includes("Upload")) {
          //上传相关
          obj["multiple"] = domItem["$multiple"];
          obj["uploadFileNum"] = domItem["$uploadFileNum"] || 1;
          obj["max"] = domItem["$maxFileSize"]
              ? parseInt(domItem["$maxFileSize"]) * 1024
              : 0; //0为无限制
          domItem["$uploadFileType"] &&
          (obj["uploadFileType"] = domItem["$uploadFileType"]);
          if (domItem["ctrl_type"] === "UploadFile") {
            obj["accept"] = "*/*";
          } else {
            obj["accept"] =
                "*image/" + (domItem["$uploadFileExts"] || "*");
          }
          index++;
          //只用作显示相关,取消vue劫持
          Object.freeze(obj);
        } else if (domItem["ctrl_type"] == "NavPosition") {

          obj["basis"]["id"] = domItem["$caption"];
          if (!this.hasPosition) {
            this.navPosition = [];
            this.hasPosition = true;
          }
          this.navPosition.push({
            ref: obj["basis"]["id"],
            name: obj.value
          });
        } else if (this.forms.indexOf(domItem["ctrl_type"]) > -1) {
          //表单元素
          if (!obj["basis"]["visible"]) {
            //对于不可见的表单元素不处理
            return false;
          }
          obj["basis"]["bindValue"] = true; //是否需要绑定value
          obj["basis"]["readOnly"] = domItem["$readOnly"];
          obj["basis"]["disabled"] = domItem["$disabled"];
          obj["basis"]["required"] = domItem["$required"]; //必填标识
          obj["basis"]["showLabel"] = domItem["$showLabel"];
          obj["error"] = false; //是否有错误
          obj["errorMsg"] = `请填写${obj["basis"]["label"]}`; //错误提示
          //将子表中的所有label定为显示
          pid && (obj["basis"]["showLabel"] = true);
          //是否是子表中的表单，记录父级id
          index++;
          if (
              domItem["ctrl_type"].includes("Text") ||
              domItem["ctrl_type"].includes("AutoComplete")
          ) {
            obj["basis"]["placeholder"] =
                domItem["$placeholder"] || "请填写";
            obj["basis"]["ishideCon"] = domItem["$ishideCon"] || false; //密码框
          }
          //默认显示,子表特殊处理
          let defaultAns = null;
          if (pid && pIndex > -1) {
            defaultAns = this.$store.state.subForm[pid][pIndex][
                domItem["metadata_fullcode"]
                ];
            //多选框值为数组格式，但是当只选择了一项，服务器会返回一个对象，所以需要处理
            if (
                domItem["ctrl_type"].includes("CheckBox") &&
                Object.prototype.toString.call(defaultAns) ===
                "[object Object]"
            ) {
              defaultAns = [defaultAns];
              obj["value"] = defaultAns;
            } else {
            }
          } else {
            defaultAns = this.$store.state.subForm[
                domItem["metadata_fullcode"]
                ];
          }
          if (defaultAns != null && defaultAns != undefined) {
            //文本框特殊处理
            if (
                domItem["ctrl_type"].includes("Text") ||
                domItem["ctrl_type"].includes("AutoComplete")
            ) {
              obj["value"] = defaultAns;
            } else {
              obj["basis"]["defaultValue"] = defaultAns;
            }
          } else {
            //未填写则显示默认值
            if (
                !!domItem["$metadata"] &&
                !!domItem["$metadata"]["defaultValue"]
            ) {
              obj["basis"]["defaultValue"] =
                  domItem["$metadata"]["defaultValue"];
            } else {
              obj["basis"]["defaultValue"] = null;
            }
          }
          //数据源
          if (
              !!dataSource &&
              dataSource[obj["basis"]["id"]] &&
              dataSource[obj["basis"]["id"]]["dataSource"]
          ) {
            obj["dataSource"] =
                dataSource[obj["basis"]["id"]]["dataSource"];
          } else {
            //数据源不存在读取静态数据
            if (
                domItem["$metadata"] &&
                domItem["$metadata"]["dataSource"] &&
                domItem["$metadata"]["dataSource"]["type"] === "static"
            ) {
              obj["dataSource"] =
                  domItem["$metadata"]["dataSource"]["code"];
            }
          }
          //验证规则
          if (
              !!domItem["$metadata"] &&
              !!domItem["$metadata"]["validate"]["config"]
          ) {
            obj["basis"]["validate"] =
                domItem["$metadata"]["validate"]["config"];
          }
        } else {
          //子表特殊显示情况
          obj["basis"]["ctrl_type"] === "Label" &&
          (obj["value"].includes("—") ||
              obj["value"].includes("-")) &&
          obj["basis"]["label"] &&
          (obj["value"] = obj["basis"]["label"]);
          //冻结只用作显示相关,取消vue劫持
          Object.freeze(obj);
        }
        //冻结只用作显示相关数据,取消vue劫持
        Object.freeze(obj["basis"]);

        //select通过修改此属性触发值更改
        if (domItem["ctrl_type"] === 'Select') {
          obj['changeVal'] = '';
        }
        return obj;
      },
      //顶部与底部
      go(pos) {
        //是否子表
        let dom = null;
        if (pos.tab) {
          for (var i = 0, length = pos.data.element.length; i < length; i++) {
            if (pos.data.element[i]['eleId'] === pos.tab.eleId) {
              break;
            }
          }
          dom = document.getElementById(pos.tabId);
        } else {
          dom = this.$refs[pos.ref];
          if (dom && dom.length > 0) {
            dom = dom[0];
          }
        }
        dom && dom.scrollIntoView();
        pos.tab && (pos.data.active = i);
      },
      navChange(obj) {
        this.navPosition.splice(this.navPosition.length - 1, 0, obj);
      },
      infoDialogClose(action, done) {
        let video = document.getElementById('icon-video');
        video && video.pause();
        let audio = document.getElementById('icon-audio');
        audio && audio.pause();
        done();
      },
      onNumberInput() {
      },
      onNumberDelete() {
      },
      // 实现移动端拖拽
      down(event) {
        let default_drag_comp = null;
        if (event.target == this.$refs["default_drag_comp2"]) {
          this.flags = 2;
          default_drag_comp = event.target;
        } else {
          this.flags = 1;
          default_drag_comp = this.$refs["default_drag_comp"];
        }
        let touch;
        if (event.touches) {
          touch = event.touches[0];
        } else {
          touch = event;
        }
        this.maxW = document.documentElement.clientWidth;
        this.maxH = document.documentElement.clientHeight;

        this.position.x = touch.clientX - default_drag_comp.offsetLeft;
        this.position.y = touch.clientY - default_drag_comp.offsetTop;
        this.dx = touch.clientX;
        this.dy = touch.clientY;
      },
      move(event) {
        let default_drag_comp =
            event.target == this.$refs["default_drag_comp2"]
                ? this.$refs["default_drag_comp2"]
                : this.$refs["default_drag_comp"];
        event.preventDefault();
        if (this.flags) {
          let touch;
          if (event.touches) {
            touch = event.touches[0];
          } else {
            touch = event;
          }
          this.nx = touch.clientX - this.position.x;
          this.ny = touch.clientY - this.position.y;

          if (this.nx < 4) {
            this.nx = 4;
          } else if (this.nx > this.maxW - 52) {
            this.nx = this.maxW - 52;
          }
          let height =
              default_drag_comp.offsetHeight + (this.showMarker ? 6 : 76);
          if (this.ny < 0) {
            this.ny = 0;
          } else if (this.ny >= this.maxH - height) {
            this.ny = this.maxH - height;
          }
          default_drag_comp.style.left = this.nx + "px";
          default_drag_comp.style.top = this.ny + "px";
          //阻止页面的滑动默认事件；如果碰到滑动问题，1.2 请注意是否获取到 touchmove
          // document.addEventListener(
          //     "touchmove",
          //     function() {
          //       event.preventDefault();
          //     },
          //     false
          // );
        }
      },
      //鼠标释放时候的函数
      end() {
        this.flags = false;
      },
      arrow() {
        this.showArrow = !this.showArrow;
      },
      //用于生成uuid
      str4() {
        return (((1 + Math.random()) * 0x10000) | 0)
            .toString(16)
            .substring(1);
      },
      guid() {
        return this.str4() + this.str4() + this.str4();
      }
    }
  };
  /**
   * 添加子表tab回调
   * @param id 增加的tab的元素id
   * @param arr 存放tab显示数据的数组
   * arr数据结构[{
   *   alias:"", //若此属性存在，则显示此属性不会显示number
   *   eleId:"", //对应tab元素Id
   *   name:"",  //tab显示的名称
   *   number:"" //默认显示的数字
   * }]
   */
