<template>
  <van-cell-group :title="showIconInfo?'':label" class="long-left">
    <van-cell v-if="showIconInfo" class="icon-cell">
      <div class="van-cell-group__title" slot="title"><IconInline :label="label" :txt="attributes.basis.dataCapion" :audio="attributes.basis.dataAudioUrl" :video="attributes.basis.dataVideoUrl"></IconInline></div>
    </van-cell>
    <van-cell v-if="attributes.basis.readOnly" :value="attributes.value||'无'" />
    <van-radio-group v-else v-model="attributes.value" @change="change">
      <van-cell-group>
        <van-cell :data-val="item.value" :class="{'van-cell--required':attributes.basis.required,'check-item':item.value==attributes.value}" v-for="item in attributes.dataSource" :key="item.value" :title="item.text" clickable @click="attributes.value=item.value">
          <van-radio :data-val="item.value" :name="item.value" :checked-color="baseColor"/>
        </van-cell>
      </van-cell-group>
    </van-radio-group>
  </van-cell-group>
</template>

<script>
  import base from '../../lib/base'
  export default {
    name: "Radio",
    extends:base,
    data() {
      return {
        // baseColor:'#eb6e2d'
      }
    },
    created: function () {
      if(!this.attributes.dataSource){
        this.attributes.dataSource=[{
          text:'是',
          value:1
        },{
          text:'否',
          value:0
        }];
        this.attributes.value={
          text:'是',
          value:1
        };
      }else{
        this.attributes.basis.defaultValue&&(this.attributes.value=this.attributes.basis.defaultValue.value)
      }
      //验证value是否为string
      if(typeof this.attributes.value ==="object"){
        this.attributes.value=this.attributes.value.value;
      }
      this.attributes.errorMsg = `请选择${this.attributes.basis.label}`;
    },
    methods: {
      change(val){
        this.attributes.error=false;
        this.emitParent(val);
      }
    },
    components: {}
  }
</script>
