<template>
  <van-cell-group :title="label+'：'+txt">
  </van-cell-group>
</template>

<script>
  import base from '../../lib/base'

  export default {
    extends: base,
    name: "DataChoice",
    data() {
      return {
        txt: "暂无数据",
      }
    },
    computed: {},
    components: {},
    created: function () {
      if (this.$store.state.subForm[this.attributes.basis.id]) {
        this.emitParent(this.$store.state.subForm[this.attributes.basis.id]);
        this.txt = this.$store.state.subForm[this.attributes.basis.id]['text'] || '暂无数据';
      }
    },
    methods: {}
  }
</script>
