<template>
  <van-cell-group :title="showIconInfo?'':label" class="long-left">
    <van-cell v-if="showIconInfo" class="icon-cell">
      <div class="van-cell-group__title" slot="title"><IconInline :label="label" :txt="attributes.basis.dataCapion" :audio="attributes.basis.dataAudioUrl" :video="attributes.basis.dataVideoUrl"></IconInline></div>
    </van-cell>
    <van-cell v-if="attributes.basis.readOnly" :value="attributes.value||'无'" />
    <van-checkbox-group v-else v-model="attributes.value" @change="change">
      <van-cell-group>
        <van-cell
          :data-val="item.value"
          v-for="item in attributes.dataSource"
          clickable
          :class="{'van-cell--required':attributes.basis.required,'check-item':attributes.value.includes(item.value)}"
          :key="item.value"
          :title="item.text"
          @click="toggle(item)"
        >
          <van-checkbox :data-val="item.value" :checked-color="baseColor" :name="item.value" ref="checkboxes" />
        </van-cell>
      </van-cell-group>
    </van-checkbox-group>
  </van-cell-group>
</template>

<script>
  import base from '../../lib/base'

  export default {
    name: "CheckBox",
    extends:base,
    data() {
      return {
        // baseColor:'#eb6e2d'
      }
    },
    created: function () {
      if(this.attributes.dataSource){
        if(this.attributes.basis.defaultValue){
          if(this.attributes.basis.defaultValue instanceof Array){
            this.attributes.value=[];
            for(let i=0,length=this.attributes.basis.defaultValue.length;i<length;i++){
              this.attributes.value.push(this.attributes.basis.defaultValue[i]['value']);
            }
          }else{
            this.attributes.value=[this.attributes.basis.defaultValue.value];//多选v-modal为Array
          }
          return
        }
      }else{
        this.attributes.dataSource=[];
      }
      this.attributes.value=[];
      this.attributes.errorMsg = `请选择${this.attributes.basis.label}`;
    },
    methods: {
      toggle(item) {
        for(let i in this.attributes.value){
          if(this.attributes.value[i]===item.value){
            this.attributes.value.splice(i,1);
            return
          }
        }
        this.attributes.value.push(item.value);
        // this.$refs.checkboxes[index].toggle();
      },
      change(val){
        this.attributes.error=false;
        this.emitParent(val);
      }
    },
    components: {}
  }
</script>
