import axios from "axios";
import qs from "qs";
import router from "../router";
import {Toast} from 'vant';

// axios.defaults.withCredentials = true; // 跨域是否允许带cookie这些,配置后需要后台response配置请求标头
const Axios = axios.create({
  baseURL: process.env.VUE_APP_API_HOST,
  timeout: 20000,
  responseType: "json",
  headers: {
    "Content-Type": "application/x-www-form-urlencoded;charset=utf-8"
  }
});

//已经请求过的请求集合
const resquestApis = [];
//过滤请求集合
const specialApis = ['login','getPageFistCommHasUphoto','getChildList','delComment','addOrCancelCommentZan'];

//POST传参序列化(添加请求拦截器)
Axios.interceptors.request.use(
  config => {
      for (var k = 0, leng = specialApis.length; k < leng; k++) {
        if (config.url.includes(specialApis[k])) {
          break;
        }
      }
      //排除是否是不需要检测的接口
      if (k === leng) {
        // 在发送请求之前,设置loading显示，检测重复请求，这里设置的1s内不能发送相同请求,不管是否响应
        let now = Date.now(), api = config['url'] + '/' + config['method'];//记录请求该接口的时间戳，下次请求的时候作比较
        let params = config.params ? JSON.stringify(config.params) : null;
        if (resquestApis.length == 0) {
          let urlObj = {
            params:params
          };
          urlObj[api] = now;
          resquestApis.push(urlObj);
        } else {
          for (var i = 0, length = resquestApis.length; i < length; i++) {
            if (resquestApis[i][api]) {
              if(resquestApis[i][api]['params']===params && now - resquestApis[i][api] < 1000){
                console.warn("恶意请求" + api);
                return false;
              }else{
                resquestApis[i][api] = now;
                resquestApis[i]['params'] = params;
                break;
              }
            }
          }
          if (i == length) {
            let urlObj = {
              params:params
            };
            urlObj[api] = now;
            resquestApis.push(urlObj);
          }
        }
      }



      if (config.method === "post" || config.method === "put") {
        // 序列化
        if (config.headers['Content-Type'] != 'multipart/form-data') {
          config.data = qs.stringify(config.data);
        }
      }

      // 若是有做鉴权token , 就给头部带上token
      // if (!!localStorage.token) {
      //   config.headers.Authorization = "Bearer " + localStorage.token;
      // }

      return config;
    }, error => {
      // error 的回调信息,看项目的定义
      Toast.fail({
        duration: 1500,
        message: '数据请求失败',
      });
      return Promise.reject(error);
    }
);

//返回状态判断(添加响应拦截器)
Axios.interceptors.response.use(
    res => {
      //对响应数据做些事,根据定义的响应格式和状态码做处理
      if (res.status === 200) {
        if (res.config.responseType === 'text') {
          return Promise.resolve(res.data);
        } else if (res.data.success||res.data.state==20001) {
          return Promise.resolve(res.data);
        } else {
          Toast.fail({
            duration: 1500,
            message: res.data.message || '请求失败,请重试',
          })
        }
        return Promise.reject(res.data);
      } else {
        return Promise.reject(res.data);
      }
    },
    error => {
      //常见错误操作
      try {
        let errCode = error && error.response && error.response.status;
        switch (errCode) {
          case 404:
            error.response.data.msg = "找不到路径";
            break;
          case 405:
            break;
        }
        Toast.fail({
          duration: 1500,
          message: (error.response &&  error.response.data && error.response.data.msg)? error.response.data.msg : '出错了，请重试',
        });
        // 返回 response 里的错误
        return Promise.reject(error.response || {});
      } catch (e) {
        console.error('err', e);
        Toast.fail({
          duration: 1500,
          message: '服务器维护中',
        });
      }
    }
);

// 对axios的实例重新封装成一个plugin ,方便 Vue.use(xxxx)
export default {
  install: function (Vue, Option) {
    Object.defineProperty(Vue.prototype, "$http", {value: Axios});
  }
};
