<template>
  <div class="btn-group">
    <template v-for="btn in attributes.buttons" v-if="btn.show!='more'">
      <!-- 保存按钮 -->
      <van-button
        v-if="btn.isSystem && (btn.actionName==='system_form_save' || btn.actionName==='system_qi_save')"
        size="large"
        :id="btn.actionName"
        :class="btn.buttonType==='auxiliary'?'':'van-button--danger'"
        :loading="$store.state.btnLoading"
        @click.stop="btnDo(btn)"
      >{{btn.text}}</van-button>

      <!-- 不是保存按钮 -->
      <van-button
        v-else
        size="large"
        :id="btn.actionName"
        :class="btn.buttonType==='auxiliary'?'':'van-button--danger'"
        @click.stop="btnDo(btn)"
      >{{btn.text}}</van-button>
    </template>

    <!-- 更多按钮 -->
    <van-button v-if="showActionBtn" size="large" @click="show=true">更多</van-button>
    <van-actionsheet v-model="show" :actions="actions" @select="onSelect" />

    <!-- window.open按钮 -->
    <van-popup v-model="showIframe" position="right">
      <Iframe @close="hideIframe"></Iframe>
    </van-popup>
  </div>
</template>

<script>
import base from "../../lib/base";
import Iframe from "../bhc/Iframe";

export default {
  name: "ButtonBar",
  extends: base,
  data() {
    return {
      show: false,
      showIframe: false,
      showActionBtn: false,
      actions: []
    };
  },
  computed: {},
  components: {
    Iframe
  },
  created: function() {
    window.btnNum = this.attributes.buttons.length;
    for (let i in this.attributes.buttons) {
      //弹出层形式按钮
      if (this.attributes.buttons[i]["show"] == "more") {
        this.showActionBtn = true;
        this.actions.push({
          name: this.attributes.buttons[i]["text"],
          type: this.attributes.buttons[i]["buttonType"],
          actionName: this.attributes.buttons[i]["actionName"]
        });
      } else {
      }
    }
  },
  mounted() {
    /**
     * 隐藏目标按钮方法
     * @param btns=>Array[save：保存，review：审核，saveAndReview：保存并审核]
     */
    window.hideBtn = function(btns) {
      if (Object.prototype.toString.call(btns) === "[object Array]") {
        let ids = {
          save: "system_form_save",
          review: "system_form_review",
          saveAndReview: "saveAndReview"
        };
        let hideNum = 0;
        btns.map(function(name) {
          let btn = document.getElementById(ids[name]);
          if (btn) {
            btn.className += " hide";
            hideNum++;
          }
        });
        if (hideNum == window.btnNum) {
          let div = document.querySelector(".van-fixed-btn-box");
          div && (div.style.display = "none");
        }
      } else {
        throw "参数只能是一个数组";
      }
    };
  },
  methods: {
    btnDo(btn) {
      if (btn["isSystem"] && btn["actionName"] == "system_window_open") {
        this.showIframe = true;
      } else if (btn["isSystem"] && btn["actionName"].includes("save")) {
        this.$emit("btnClick", "save",btn);
      } else if (btn["isSystem"] && btn["actionName"].includes("close")) {
        window.wx && window.wx.miniProgram.navigateBack();
      } else {
        this.$emit("btnClick",false,btn)
      }
    },
    onSelect(item) {
      // 点击选项时默认不会关闭菜单，可以手动关闭
      this.show = false;
      this.btnDo(item);
    },
    hideIframe() {
      this.showIframe = false;
    }
  }
};
</script>
