<template>
  <div class="van-icon-info-box">
    {{label}}<van-icon v-if="txt" @click="iconClick('info')" name="question-o" />
    <van-icon v-if="audio" @click="iconClick('audio')" name="music-o" />
    <van-icon v-if="video" @click="iconClick('video')" name="play-circle-o" />
  </div>
</template>

<script>
  export default {
    name: "IconInline",
    data() {
      return {}
    },
    props:['label','txt','audio','video'],
    computed: {},
    components: {},
    created: function () {

    },
    methods: {
      iconClick(type){
        if(type==='info'){
          this.$store.state.dialogInfoType='txt';
          this.$store.state.dialogInfoSource=this.txt;
        }else if(type==='audio'){
          this.$store.state.dialogInfoType='audio';
          this.$store.state.dialogInfoSource=this.audio;
        }else{
          this.$store.state.dialogInfoType='video';
          this.$store.state.dialogInfoSource=this.video;
        }
        this.$store.state.showDialogInfo=true;
      }
    }
  }
</script>
