<template>
  <div :id="commentID" v-if="!(componentName=='buttonBar' && $route.query.readonly==1)" :class="['form-item',{'van-btn-box van-fixed-btn-box':componentName==='buttonBar'},{'error':formObj.error},{'hide-item':formObj.exclude || !formObj.basis.visible},{'readonly-container':formObj.basis.readOnly}]" :pid="formObj.basis.pid">
    <!--数据相关组件需要监听事件分发,表单相关双向绑定value-->
    <component v-if="formObj.basis.bindValue" :is="componentName" v-model="formObj.value" :attributes="formObj"></component>
    <component v-else-if="componentName==='buttonBar'" :is="componentName" :attributes="formObj"
               v-on="$listeners"></component>
    <!--数据无须双向绑定或只做显示-->
    <component v-else :is="componentName" :attributes="formObj"></component>
    <p class="van-item_tip">{{formObj.errorMsg||'填写有误'}}</p>
  </div>
</template>

<script>
  import Input from '@/components/bhc/Input'
  import Radio from '@/components/bhc/Radio'
  import Select from '@/components/bhc/Select'
  import CheckBox from '@/components/bhc/CheckBox'
  import DatePicker from '@/components/bhc/DatePicker'
  import DateIntervalPicker from '@/components/bhc/DateIntervalPicker'
  import Uploader from '@/components/bhc/Uploader'
  import Rank from '../teas/rank/Index'
  import DataChoice from '@/components/common/DataChoice'
  import Label from '@/components/common/Label'
  import ButtonBar from '@/components/common/ButtonBar'
  import AutoComplete from '@/components/bhc/AutoComplete'

  export default {
    name: "FormItem",
    props: {
      formObj: {
        type: Object,
        default() {
          return {}
        }
      },
      eleId:{
        type:String,
        default:""
      }
    },
    components: {
      inputCrl: Input,
      radioCrl: Radio,
      selectCrl: Select,
      datePickerCrl: DatePicker,
      checkBoxCrl: CheckBox,
      dateIntervalPicker: DateIntervalPicker,
      buttonBar: ButtonBar,
      rank: Rank,
      uploader: Uploader,
      dataChoice: DataChoice,
      labelCrl: Label,
	  autocomplete: AutoComplete
    },
    data() {
      return {}
	},
    computed: {
      // 重命名注册组件的原因：一些组件参数需要修改并且指向同一或不同组件
      componentName: function () {
        if (this.formObj.basis.ctrl_type) {
          switch (this.formObj.basis.ctrl_type) {
            case 'DataChoice':
              return 'dataChoice'
            case 'RadioBox':
              return 'radioCrl'
            case 'Select':
              return 'selectCrl'
            case 'CheckBox':
              return 'checkBoxCrl'
            case 'Datepicker':
            case 'TimePicker':
              return 'datePickerCrl'
            case 'DateIntervalPicker':
              return 'dateIntervalPicker'
            case 'TextBox':
              return 'inputCrl'
            case 'TextArea':
              this.formObj.type = 'textarea';
              return 'inputCrl'
            case 'ButtonBar':
              return 'buttonBar'
            case 'Rank':
              return 'rank'
            case 'Label':
            case 'Title3':
            case 'Title4':
            case 'Title5':
            case 'Title6':
			  return 'labelCrl'
			case 'AutoComplete':
			  return 'autocomplete'
              // case 'UploadPhoto':
              // case 'UploadImg':
              // case 'UploadFile':
              //   return 'uploader'
          }
        }
        return ''
      },
      commentID:function () {
		let id=this.formObj.basis.id.replace(/\./g,'-');
        if(id){
          id = this.formObj.basis.pid?(id+'--'+this.eleId):id
        }else{
          id = ''
		}
		window.$mobile_ctrl[id] = this.formObj;
		return id;
      }
    },
    methods: {

    }
  }
</script>
