<template>
  <div class="van-font0 p10">
    <van-button size="small" v-for="(item,index) in types" @click="check(index)" :class="{'van-button--danger':selectedVal.pIndex==index}">{{selectedVal&&selectedVal.pIndex==index?selectedVal.text:item}}</van-button>
    <van-popup v-model="show" position="bottom">
      <van-picker
          show-toolbar
          :title="label"
          :columns="columns"
          :default-index="cindex"
          @cancel="onCancel"
          @confirm="onConfirm"
      />
    </van-popup>
  </div>
</template>

<script>
  import rank from './rank'

  export default {
    name: "RankSelect",
    mixins:[rank],
    data() {
      return {
        actions: [],
        types :['优秀', '良好', '一般', '差'],
        selectedVal:'',
        cindex:0,
        show:false,
        columns:[],//弹出层显示的数据
        label:""
      }
    },
    computed: {},
    components: {},
    created: function () {
      for (let i = 0, length = this.types.length; i < length; i++) {
        let arr = [];
        switch (i) {
          case 0:
            for (let n = 100; n > 85; n--) {
              arr.push({
                text: this.types[i] + n,
                value: n,
                pIndex:i
              })
            }
            break;
          case 1:
            for (let n = 85; n > 75; n--) {
              arr.push({
                text: this.types[i] + n,
                value: n,
                pIndex:i
              })
            }
            break;
          case 2:
            for (let n = 75; n > 59; n--) {
              arr.push({
                text: this.types[i] + n,
                value: n,
                pIndex:i
              })
            }
            break;
          case 3:
            for (let n = 59; n > 0; n--) {
              arr.push({
                text: this.types[i] + n,
                value: n,
                pIndex:i
              })
            }
            break;
        }
        this.actions.push(arr);
      }
      if(this.val){
        let val=+this.val,aIndex=0;
        if(val>85){
          aIndex=0;
        }else if(val>75){
          aIndex=1;
        }else if(val >60){
          aIndex=2;
        }else{
          aIndex=3;
        }
        this.cindex=this.getItemInArr(this.val,this.actions[aIndex]);
        let ck=this.actions[aIndex][this.cindex];
        this.onConfirm(ck);
      }
    },
    methods: {
      check(i){
        this.label=this.types[i];
        this.columns=this.actions[i];
        this.cindex=this.selectedVal?+this.getItemInArr(this.selectedVal.value,this.columns):0;
        this.show=true;
      },
      onConfirm(val) {
        this.selectedVal=val;
        this.show=false;
        this.$emit('changeVal',val,this.obj);
      },
      onCancel() {
        this.show=false
      },
      getItemInArr(val,arr){
        for(let i in arr){
          if(arr[i]['value']==val){
            return i
          }
        }
        return 0
      }
    }
  }
</script>
