<template>
  <div class="review-item">
    <div class="review-item-title">
      <div class="review-item-info" @click.stop="goErr">{{(info.index!=undefined?'Tab'+(info.index+1)+'：':'')+info.errorMsg}}</div>
      <div v-if="info.level<1" class="review-item-edit" @click.stop="edit">
        <van-icon name="edit"/>
      </div>
    </div>
    <div v-show="showEdit&&info.level<1" class="review-item-area">
      <van-field
          v-model="info.remark"
          type="textarea"
          placeholder="请输入审核信息..."
          rows="2"
          @blur="onBlur"
          autosize
      />
    </div>
  </div>
</template>

<script>
  export default {
    name: "ReView",
    props: {
      info: {
        type: Object,
        default: function () {
          return {}
        }
      }
    },
    data() {
      return {
        showEdit: true
      }
    },
    components: {},
    methods: {
      onBlur(){
        if(this.info.remark.length>0){
          for(let i=0,length=window.ev.evList.length;i<length;i++){
            if(this.info.key===window.ev.evList[i]['key']){
              //找到已填写备注的pageCurrent对象设置error
              let num=0;//统计是否设置了审核规则中所有控件数
              for(let p=0,pageNum=window.pageCurrentData.length;p<pageNum;p++){
                //是否是子表
                if(window.ev.evList[i]['prop']){
                  if(window.pageCurrentData[p]['basis']['ctrl_type']==="SubTableVertical"){
                    for(let c=0,childLength=window.pageCurrentData[p]['items'][this.info.index].length;c<childLength;c++){
                      if(window.ev.evList[i]['rel'].indexOf(window.pageCurrentData[p]['items'][this.info.index][c]['basis']['$caption'])>-1){
                        window.pageCurrentData[p]['items'][this.info.index][c]['error']=false;
                        num++;
                        if(num==window.ev.evList[i]['rel'].length){
                          return false
                        }
                      }
                    }
                  }
                }else{
                  if(window.ev.evList[i]['rel'].indexOf(window.pageCurrentData[p]['basis']['$caption'])>-1){
                    window.pageCurrentData[p]['error']=false;
                    num++;
                    if(num==window.ev.evList[i]['rel'].length){
                      return false
                    }
                  }
                }
              }
              break;
            }
          }
        }
      },
      edit() {
        this.showEdit = !this.showEdit;
      },
      goErr(){
        //查找对应控件id
        let key="";
        for(let i=0,length=window.ev.evList.length;i<length;i++){
          if(window.ev.evList[i]['key'].toLowerCase()===this.info.key.toLowerCase()){
            key=window.ev.evList[i]['rel'][0];
            break;
          }
        }
        if(!key){
          return false
        }
        //是否子表
        if(!isNaN(+this.info.index)){
          for(let i=0,length=window.pageCurrentData.length;i<length;i++){
            if(window.pageCurrentData[i]['basis']['ctrl_type']==='SubTableVertical'){
              for(let n=0,items=window.pageCurrentData[i]['items'].length;n<items;n++){
                for(let child=0,children=window.pageCurrentData[i]['items'][n].length;child<children;child++){
                  if(window.pageCurrentData[i]['items'][n][child]['basis']['$caption']===key){
                    window.pageCurrentData[i]['active']=+this.info.index;
                    this.$nextTick(()=>{
                      let ele=window.pageCurrentData[i]['items'][n][child]['basis']['id'].replace(/\./g,'-')+'--'+ window.pageCurrentData[i]['element'][+this.info.index]['eleId'];
                      let div=document.getElementById(ele);
                      div.scrollIntoView();
                    });
                    return
                  }
                }
              }
              break;
            }
          }
        }else{
          for(let i=0,length=window.pageCurrentData.length;i<length;i++){
            if(window.pageCurrentData[i]['basis']['$caption']===key){
              let ele=window.pageCurrentData[i]['basis']['id'].replace(/\./g,'-');
              let div=document.getElementById(ele);
              div.scrollIntoView();
              return
            }
          }
        }
      },
    }
  }
</script>
