import Vue from 'vue'
import App from './bhc.vue'
import axios from '@/lib/http'
import store from '@/store'
import '@/lib/flexble'
import '@/lib/window'
import '@/assets/css/common.less'

import {
  NavBar,
  Button,
  DatetimePicker,
  Dialog,
  Toast,
  Field,
  Cell,
  CellGroup,
  Card,
  RadioGroup,
  Radio,
  Checkbox,
  CheckboxGroup,
  Popup,
  Picker,
  Rate,
  Slider,
  Area,
  Actionsheet,
  Uploader,
  Icon,
  PullRefresh,
  List, Tab, Tabs, NumberKeyboard, SwipeCell
} from 'vant'

Vue.use(axios).use(Button).use(Toast).use(NavBar).use(Field).use(Cell).use(CellGroup).use(RadioGroup).use(Area)
    .use(Checkbox).use(CheckboxGroup).use(Radio).use(Picker).use(Popup).use(DatetimePicker).use(Slider).use(Rate)
    .use(Actionsheet).use(Uploader).use(Icon).use(Card).use(PullRefresh).use(List).use(Dialog).use(Tab).use(Tabs)
    .use(NumberKeyboard).use(SwipeCell)

Vue.config.productionTip = false

// load进度条
import NProgress from 'nprogress'
import 'nprogress/nprogress.css'
NProgress.configure({easing: 'ease-in', minimum: 0.1, showSpinner: false});

//全局组件
import Load from '@/components/common/Load'
Vue.component("Load", Load);
import IconInline from '@/components/common/IconInline'
Vue.component("IconInline", IconInline);

