import Router from 'vue-router'

Vue.use(Router);

const router = new Router({
  routes: [
    //  基础表单相关路由
    {
      path: '/',
      alias: '/index',
      name: 'Form',
      component: require('@/views/bhc/Index').default,
    },
    // {
    //   path: '/index/next',
    //   name: 'Next',
    //   component: () => import('@/views/bhc/Next'),
    //   meta:{
    //     showNav:true
    //   }
    // },
    // {
    //   path: '/index/next/*',
    //   component: () => import('@/views/bhc/Next'),
    //   meta:{
    //     showNav:true
    //   }
    // },
    {
      path: '/empty',
      name: 'Empty',
      component: require('@/views/Empty.vue').default
    },
    //  404
    {
      path: '*',//404
      component: require('@/views/404.vue').default
    }
  ]
})

//路由监听
router.beforeEach((to, from, next) => {
  NProgress.start();
  next();
})
router.afterEach((to, from) => {
  NProgress.done()
})

new Vue({
  router,
  store,
  render: h => h(App),
}).$mount('#app')
