<template>
  <van-cell-group v-if="attributes.basis.ctrl_type==='QA' && attributes.basis.showLabel">
    <van-cell class="myTitle">
      <template slot="title">
        <span class="van-cell-group__title">{{label}}</span>
      </template>
    </van-cell>
    <van-field
        v-model="attributes.value"
        :readonly="attributes.basis.readOnly"
        :type="type"
        :disabled="attributes.basis.disabled"
        :placeholder="attributes.basis.readOnly?'':attributes.basis.placeholder"
        :error="attributes.error"
        :maxlength="maxlength"
        :minlength="minlength"
        :required="attributes['basis']['required']"
        @focus="inputFocus"
        @blur="inputBlur"
    />
  </van-cell-group>
  <van-cell-group v-else-if="showIconInfo">
    <van-cell class="icon-cell">
      <div class="van-cell-group__title" slot="title">
        <IconInline :label="label" :txt="attributes.basis.dataCapion" :audio="attributes.basis.dataAudioUrl" :video="attributes.basis.dataVideoUrl"></IconInline>
      </div>
    </van-cell>
    <van-field
        v-if="attributes.basis.ctrl_type!=='QA' && attributes.basis.showLabel&&labelInline&&attributes.basis.type!=='textarea'&&attributes.basis.label&&attributes.basis.label.length<=7"
        v-model="attributes.value"
        :placeholder="attributes.basis.readOnly?'':attributes.basis.placeholder"
        :error="attributes.error"
        :readonly="attributes.basis.readOnly"
        :disabled="attributes.basis.disabled"
        :maxlength="maxlength"
        :minlength="minlength"
        :required="attributes['basis']['required']"
        :type="type"
        @focus="inputFocus"
        @blur="inputBlur"
    />
    <van-field
        v-else
        v-model="attributes.value"
        :readonly="attributes.basis.readOnly"
        :type="type"
        :disabled="attributes.basis.disabled"
        :placeholder="attributes.basis.readOnly?'':attributes.basis.placeholder"
        :error="attributes.error"
        :maxlength="maxlength"
        :minlength="minlength"
        :required="attributes['basis']['required']"
        @focus="inputFocus"
        @blur="inputBlur"
    />
  </van-cell-group>
  <van-cell-group v-else :title="attributes.basis.showLabel&&(label.length>7 || attributes.basis.type==='textarea')?label:''">
    <van-field
        v-if="attributes.basis.ctrl_type!=='QA' && attributes.basis.showLabel&&labelInline&&attributes.basis.type!=='textarea'&&attributes.basis.label&&attributes.basis.label.length<=7"
        v-model="attributes.value"
        :label="attributes.basis.label"
        :placeholder="attributes.basis.readOnly?'':attributes.basis.placeholder"
        :error="attributes.error"
        :readonly="attributes.basis.readOnly"
        :disabled="attributes.basis.disabled"
        :maxlength="maxlength"
        :minlength="minlength"
        :required="attributes['basis']['required']"
        :type="type"
        @focus="inputFocus"
        @blur="inputBlur"
    />
    <van-field
        v-else
        v-model="attributes.value"
        :readonly="attributes.basis.readOnly"
        :type="type"
        :disabled="attributes.basis.disabled"
        :placeholder="attributes.basis.readOnly?'':attributes.basis.placeholder"
        :error="attributes.error"
        :maxlength="maxlength"
        :minlength="minlength"
        :required="attributes['basis']['required']"
        @focus="inputFocus"
        @blur="inputBlur"
    />
  </van-cell-group>
</template>

<script>
  import base from '../../lib/base'

  export default {
    extends: base,
    name: "Input",
    data() {
      return {
        validFun: null,//验证规则函数
        showError:false,//显示错误
        labelInline:true,//控制行内标签
        error:false,//是否有错误
        // top:0,//聚焦时记录触发时y方向滑动位置
        maxlength:50,
        minlength:0,
        max:9999999,//数字模式下最大值
        min:0,
        type:'text'
      }
    },
    created: function () {
      //是否隐藏行内label
      if(this.attributes.basis.hideLabel){
        this.labelInline=false;
      }
      //输入框类型
      if (this.attributes.basis.ctrl_type==='TextArea' || this.attributes.basis.type === 'textarea') {
        this.type = 'textarea';
      }
      if(this.attributes.basis.ishideCon){
        this.type = 'password';
      }
      //验证规则
      if (this.attributes.basis.validate) {
        //是否数字
        if (this.attributes.basis.validate.isNumber == 1) {
          this.type = 'number';
        }
        //验证
        if (this.attributes.basis.validate.express) {
          this.validFun = this.attributes.basis.validate.express;
        }
        //数字输入max为最大值
        if (this.attributes.basis.validate.max) {
          this.maxlength = +this.attributes.basis.validate.max;
          this.max = +this.attributes.basis.validate.max;
        }
        if (this.attributes.basis.validate.min) {
          this.minlength = +this.attributes.basis.validate.min;
          this.min = +this.attributes.basis.validate.min;
        }
        // !this.attributes.basis.maxlength
        if (!this.attributes.basis.validate.max||this.type==='number') {
          if (this.type === 'textarea') {
            this.maxlength = 100;
          } else {
            this.maxlength = 50;
          }
        }
      }

      //默认
      this.attributes.basis.defaultValue&&(this.attributes.value = this.attributes.basis.defaultValue.text);
      this.attributes.value==null&&(this.attributes.value="");
    },
    methods: {
      inputFocus(e) {
        if(!this.attributes.basis.readOnly && window.pageCurrentData){
          let parent=window.findClassParent(e.target,'form-item');
          //聚焦滚动处理
          parent.scrollIntoView();
          // if(document.body.offsetHeight-parent.offsetTop-parent.offsetHeight>window.innerHeight/2){
          //   parent.scrollIntoView();
          // }else{
            //输入框距离底部距离小于当前窗口高度的一半，滚动到底部处理
            // parent.scrollIntoView(false);
            // let btnBoxHeight=document.querySelector(".van-fixed-btn-box").offsetHeight;
            // document.documentElement.scrollTop+=btnBoxHeight
          // }
          window.$mobile_page.currentFocusInput=window.findClassParent(e.target,'form-item');
          this.attributes.error=false;
          // 判断下一题是否是输入框，存储，子表需特殊处理
          let input=null,next=null;
          //是否子表
          if(window.pageCurrentData&&window.pageCurrentData[this.attributes.basis.num]['basis']['ctrl_type']==='SubTableVertical'){
            next=window.getNextSibilingsNode(parent);
            next&&(input=next.querySelector('input'));
          }else{
            //找到下一个非显示控件
            let has=false;
            for(var n=this.attributes.basis.num+1,length=window.pageCurrentData.length;n<length;n++){
              if(window.pageCurrentData[n]['basis']['id']&&window.pageCurrentData[n]['basis']['ctrl_type']!='TextBox'){
                break
              }else if(window.pageCurrentData[n]['basis']['ctrl_type']==='TextBox'){
                has=true;
                break
              }
            }
            if(has&&window.pageCurrentData&&window.pageCurrentData[n]){
              let nextInputId=window.pageCurrentData[n].basis.id.replace(/\./g,'-');
              let parent = document.getElementById(nextInputId);
              window.$mobile_page.nextInputId = null;
              input=parent.querySelector("input");
              next=window.findClassParent(input,'form-item');
            }
          }
          if(next&&input){
            window.$mobile_page.nextInputParent=next;
            window.$mobile_page.nextInput=input;
          }else{
            window.$mobile_page.nextInputParent=null;
            window.$mobile_page.nextInput=null
          }
        }else{
          return false
        }
        // this.top=window.pageYOffset
        //     || document.documentElement.scrollTop
        //     || document.body.scrollTop
        //     || 0;
      },
      inputBlur() {
        if(!this.attributes.basis.readOnly){
          // setTimeout(()=>{
          //   window.scrollTo(0, this.top);
          // },200);
          this.attributes.focus=false;
          if(!this.attributes['basis']['validate']&&this.attributes['basis']['validate']&&this.attributes['basis']['validate']['required']&&this.attributes.value===''){
            this.attributes.error=false;
            return false
          }
          if(this.attributes['basis']['validate']&&this.attributes['basis']['validate']&&this.attributes['basis']['validate']['required']&&!this.attributes.value){
            this.attributes.error=true;
            this.attributes.errorMsg = `请填写${this.attributes.basis.label}`;
            return false
          }
          //长度或者最大小值验证
          if (this.type==='number') {
            if(this.attributes.value<this.min||this.attributes.value>this.max){
              this.attributes.errorMsg = `请填写${this.min}到${this.max}之间的数`;
              this.attributes.error=true;
              this.$toast({
                duration:1500,
                message:this.attributes.errorMsg
              });
              return false
            }
          }else{
            if(this.attributes.value.length<this.minlength||this.attributes.value.length>this.maxlength){
              this.attributes.errorMsg = `填写长度在${this.minlength}到${this.maxlength}位`;
              this.attributes.error=true;
              this.$toast({
                duration:1500,
                message:this.attributes.errorMsg
              });
              return false
            }
          }
          //规则验证
          if(this.validFun){
            let ok = false;
            switch (this.validFun) {
              case 'isMobile':
                ok = this.isMobile();
                break;
              case 'isIDCard':
                ok = this.isIDCard();
                break;
              case 'isTelPhone':
                ok = this.isTelPhone();
                break;
              case 'isMobileOrTelPhone':
                ok = this.isMobileOrTelPhone();
                break;
              case 'isEmail':
                ok = this.isMobileOrTelPhone();
                break;
              case 'isPlateNumber':
                ok = this.isPlateNumber();
                break;
            }
            if(!ok){//验证未通过
              this.$toast({
                duration:1500,
                message:this.attributes.errorMsg
              });
              this.attributes.error=true;
              return false
            }else {}
          }
          if(this.type==='number'&&isNaN(this.attributes.value)){
            this.attributes.errorMsg = '只能输入数字';
            this.attributes.error=true;
            this.$toast({
              duration:1500,
              message:this.attributes.errorMsg
            });
            return false
          }
          this.attributes.error=false;
          this.emitParent(this.attributes.value);
        }else{
          return false
        }
      },
      isMobile() {
        if (!(/^1[3456789]\d{9}$/.test(this.attributes.value))) {
          this.attributes.errorMsg = "请填写正确的手机号码";
          return false
        }
        return true
      },
      //身份证
      isIDCard() {
        if (!(/(^\d{15}$)|(^\d{18}$)|(^\d{17}(\d|X|x)$)/.test(this.attributes.value))) {
          this.attributes.errorMsg = "请填写正确的身份证号码";
          return false
        }
        return true
      },
      isTelPhone() {
        if (!(/^(\(\d{3,4}\)|\d{3,4}-|\s)?\d{7,14}$/.test(this.attributes.value))) {
          this.attributes.errorMsg = "请填写正确的电话号码";
          return false
        }
        return true
      },
      isMobileOrTelPhone() {
        if (this.isMobile(this.attributes.value) || this.isTelPhone(this.attributes.value)) {
          return true
        }
        this.attributes.errorMsg = "请填写正确的联系方式";
        return false
      },
      isEmail() {
        if (!(/^([a-zA-Z]|[0-9])(\w|\-)+@[a-zA-Z0-9]+\.([a-zA-Z]{2,4})$/.test(this.attributes.value))) {
          this.attributes.errorMsg = "请填写正确的Email";
          return false
        }
        return true
      },
      //车牌号
      isPlateNumber() {
        var xreg = /^[京津沪渝冀豫云辽黑湘皖鲁新苏浙赣鄂桂甘晋蒙陕吉闽贵粤青藏川宁琼使领A-Z]{1}[A-Z]{1}(([0-9]{5}[DF]$)|([DF][A-HJ-NP-Z0-9][0-9]{4}$))/;
        var creg = /^[京津沪渝冀豫云辽黑湘皖鲁新苏浙赣鄂桂甘晋蒙陕吉闽贵粤青藏川宁琼使领A-Z]{1}[A-Z]{1}[A-HJ-NP-Z0-9]{4}[A-HJ-NP-Z0-9挂学警港澳]{1}$/;
        if (this.attributes.value.length == 7) {
          if (creg.test(this.attributes.value)) {
            return true
          }
        } else if (this.attributes.value.length == 8) {
          if (xreg.test(this.attributes.value)) {
            return true
          }
        } else {
          this.attributes.errorMsg = "请填写正确的车牌号";
          return false
        }
      },

    },
    components: {}
  }
</script>
