<template>
  <van-cell-group :title="showIconInfo?'':(label && label.length>8)?label:''">
    <van-cell v-if="showIconInfo" class="icon-cell">
      <div class="van-cell-group__title" slot="title"><IconInline :label="label" :txt="attributes.basis.dataCapion" :audio="attributes.basis.dataAudioUrl" :video="attributes.basis.dataVideoUrl"></IconInline></div>
    </van-cell>
    <van-cell
		:class="{'van-cell--required':attributes.basis.required,
		'alignRight':showIconInfo||attributes.basis.label.length>8}"
		:title="(showIconInfo||attributes.basis.label.length>8)?'':attributes.basis.label" is-link arrow-direction="down" :value="showTxt" @click="show=true" />
    <van-popup v-model="show" position="bottom">
      <van-picker
        show-toolbar
        :title="attributes.basis.label"
        :columns="attributes.dataSource"
        :default-index="selected"
        @cancel="onCancel"
        @confirm="onConfirm"
      />
    </van-popup>
  </van-cell-group>
</template>

<script>
  import base from '../../lib/base'

  export default {
    name: "Select",
    extends:base,
    data() {
      return {
        show:false,
        selected:0//索引，select选中控制
      }
    },
    created: function () {
      //初始化items以及默认值
      if(!this.attributes.dataSource){
        this.attributes.dataSource=[];
        this.attributes.value="";
      }else{
        if(this.attributes.basis.defaultValue){
          this.attributes.value=this.attributes.basis.defaultValue;
          for(let i in this.attributes.dataSource){
            if(this.attributes.dataSource[i]['value']===this.attributes.value.value){
              this.selected=+i;
              return
            }
          }
        }
      }
      this.attributes.errorMsg = `请选择${this.attributes.basis.label}`;
    },
    computed: {
      showTxt(){
        if(this.attributes.value===0||!!this.attributes.value){
          return this.attributes.dataSource[this.selected]['text']
        }else{
          return ''
        }
      },
      changeVal(){
        return this.attributes.changeVal
      }
    },
    watch:{
      changeVal(val){
        if(typeof val !='string'&&typeof val !='number'){
          return false
        }else{
          this.change(val);
        }
      }
    },
    methods: {
      onConfirm(val, index) {
        this.selected=index;
        this.attributes.value=val;
        this.show=false;
        this.attributes.error=false;
        this.emitParent(val);
      },
      onCancel() {
        this.show=false
      },
      change(val){
        for(let i=0,length=this.attributes.dataSource.length;i<length;i++){
          if(val==this.attributes.dataSource[i]['value']){
            this.onConfirm(this.attributes.dataSource[i],i);
            return
          }
        }
        console.info('不存在的select索引');
      }
    },
    components: {}
  }
</script>
