<template>
  <van-cell-group :title="label">
    <div class="upload-box van-padding">
        <div class="van-upload-img" v-for="(img,index) in files">
          <div class="van-del-img" @click="remove(index)">+</div>
          <img :src="img.content" alt="">
        </div>
        <van-uploader :accept="accept" :multiple="attributes.basis.uploadFileNum>1?true:false" :max-size="max" :after-read="onRead" @oversize="oversize">
          <div class="van-upload">
            <van-icon v-if="attributes.basis.accept.includes('image')" name="photograph"></van-icon>
            <van-icon v-else name="add-square"></van-icon>
          </div>
        </van-uploader>
      </div>
  </van-cell-group>
</template>

<script>
  import base from '../../lib/base'

  export default {
    name: "Uploader",
    extends: base,
    data() {
      return {
        accept:'image/*',
        max:1048576,
        files:[]
      }
    },
    computed: {},
    components: {},
    created: function () {
      console.log(this.attributes);
      if(this.attributes.basis.accept){
        this.accept="image/*";
      }
      if(this.attributes.basis.max){
        this.max=1048576;
      }
    },
    methods: {
      onRead(file) {
        console.log(file)
        if(file instanceof Array){//多选返回数组,单选返回对象
          this.files=this.files.concat(file);
        }else{
          this.files.push(file);
        }
      },
      oversize(){
        this.$toast({
          message:'上传文件大小不能超过'+(this.max/1024).toFixed(0)+'KB',
          duration:1500
        });
      },
      remove(i){
        this.files.splice(i,1);
      }
    }
  }
</script>
