<template>
  <van-cell-group :title="showIconInfo?'':label">
    <van-cell v-if="showIconInfo" class="icon-cell">
      <div class="van-cell-group__title" slot="title">
        <IconInline :label="label" :txt="attributes.basis.dataCapion" :audio="attributes.basis.dataAudioUrl"
                    :video="attributes.basis.dataVideoUrl"></IconInline>
      </div>
    </van-cell>
    <van-cell
        :class="{'van-cell--required':attributes.basis.required}"
        :title="type==='date'?'选择日期':'选择时间'"
        is-link
        arrow-direction="down"
        :value="showTime"
        @click="show=(attributes.basis.readOnly?false:true)"
    />

    <van-popup v-model="show" @closed="onCancel" position="bottom">
      <van-datetime-picker
          v-model="currentDate"
          :min-date="minData"
          :type="type"
          :title="attributes.basis.label"
          :show-toolbar="true"
          :formatter="formatter"
          :item-height="30"
          @cancel="onCancel"
          @confirm="onConfirm"
      />
    </van-popup>
  </van-cell-group>
</template>

<script>
  import base from "../../lib/base";

  export default {
    name: "DatePicker",
    extends: base,
    data() {
      return {
        show: false,
        type: "date",
        selected: 0, //索引
        currentDate: new Date(),
        minData: new Date(1919, 1, 1),
        timeFormat: "",
        showFormat: ''
      };
    },
    props: {},
    created: function () {
      let timeFormat = this.attributes["basis"].timeFormat;
      let chooseType = this.attributes["basis"].chooseType;
      this.attributes.value = "";
      this.attributes.errorMsg = `请选择${this.attributes.basis.label}`;

      //判断是日期还是时间
      if (timeFormat === "1") {
        this.type = "date";
        this.timeFormat = "yyyy/MM/dd";
        this.showFormat = "yyyy-MM-dd";
      } else if (timeFormat === "2") {
        this.type = "date";
        this.timeFormat = "yyyy/MM/dd";
        this.showFormat = "yyyy年MM月dd日";
      } else if (timeFormat === "3") {
        this.type = "year-month";
        this.timeFormat = "yyyy/MM";
        this.showFormat = "yyyy年MM月";
      } else {
        this.type = "time";
        this.timeFormat = "hh:mm";
        this.showFormat = "hh:mm";
      }

      if ((chooseType == 'datetime' || chooseType == 'datetime_s') && this.type != "time") {
        this.type = "datetime";
        this.timeFormat += (chooseType == 'datetime' ? " hh:mm" : " hh:mm:ss");
      }

      if (!!this.attributes["basis"]["defaultValue"]) {
        this.attributes.value = this.attributes["basis"]["defaultValue"];
        this.currentDate = this.type === 'time' ? this.attributes.value : new Date(this.attributes.value);
      } else {
        this.type === 'time' && (this.currentDate = "00:00");
      }
    },
    computed: {
      showTime() {
        return this.type === 'time' ? this.attributes.value : !this.attributes.value ? '' : this.setDate(new Date(this.attributes.value));
      }
    },
    methods: {
      onConfirm(date, b, c) {
        this.show = false;
        this.attributes.value = (typeof date === 'string') ? date : date.Format(this.timeFormat);
        this.currentDate = this.type === "time" ? this.attributes.value : new Date(this.attributes.value);
        this.emitParent(this.attributes.value);
      },
      setDate(date) {
        if (date && date.Format) {
          return date.Format(((this.attributes["basis"].chooseType == 'datetime' || this.attributes["basis"].chooseType == 'datetime') && this.type != "time") ? this.timeFormat : this.showFormat);
        }
      },
      onCancel() {
        this.show = false;
      },
      formatter(type, value) {
        if (type === "year") {
          return `${value}年`;
        } else if (type === "month") {
          return `${value}月`;
        } else if (type === "day") {
          return `${value}日`;
        }
        return value;
      }
    },
    components: {}
  };
</script>
