<template>
  <van-cell-group :title="showIconInfo?'':attributes.basis.showLabel&&label.length>7?label:''">
    <van-cell v-if="showIconInfo" class="icon-cell">
      <div class="van-cell-group__title" slot="title"><IconInline :label="label" :txt="attributes.basis.dataCapion" :audio="attributes.basis.dataAudioUrl" :video="attributes.basis.dataVideoUrl"></IconInline></div>
    </van-cell>
    <van-field
        v-if="!showIconInfo&&attributes.basis.showLabel&&labelInline&&attributes.basis.label&&attributes.basis.label.length<=7"
        v-model="attributes.value"
        :label="attributes.basis.label"
        :placeholder="attributes.basis.readOnly?'':attributes.basis.placeholder"
        :error="attributes.error"
        :readonly="attributes.basis.readOnly"
        :disabled="attributes.basis.disabled"
        :maxlength="maxlength"
        :minlength="minlength"
        :required="attributes['basis']['required']"
        @focus="inputFocus"
    />
    <van-field
        v-else
        v-model="attributes.value"
        :readonly="attributes.basis.readOnly"
        :disabled="attributes.basis.disabled"
        :placeholder="attributes.basis.readOnly?'':attributes.basis.placeholder"
        :error="attributes.error"
        :maxlength="maxlength"
        :minlength="minlength"
        :required="attributes['basis']['required']"
        @focus="inputFocus"
        @input="changeV"
    />

    <van-popup
      class="van-autocomplete-popup"
      v-model="showPop"
      :overlay="false"
    >
     <div class="autocomplete-box">
       <van-cell-group class='autocomplete-input'>
         <van-field
             v-model="attributes.value"
             :placeholder="'请输入'"
             :error="attributes.error"
             :maxlength="maxlength"
             :minlength="minlength"
             :required="attributes['basis']['required']"
             :clearable = "true"
             @input="changeV"
         >
           <van-icon name="arrow-left" slot='left-icon' @click='inputBlur(),showPop=false' />
           <!--          <van-button slot="button"  @click='inputBlur();showPop=false' size="small">确定</van-button>-->
         </van-field>
       </van-cell-group>
       <van-list>
         <van-cell
             v-for="item in list"
             :key="item.label"
             :title="item.label"
             @click='chooseItem(item)'
         />
       </van-list>
     </div>
    </van-popup>
  </van-cell-group>
</template>

<script>
  import base from '../../lib/base'

  export default {
    extends: base,
    name: "Input",
    data() {
      return {
        validFun: null,//验证规则函数
        showError:false,//显示错误
        labelInline:true,//控制行内标签
        error:false,//是否有错误
        // top:0,//聚焦时记录触发时y方向滑动位置
        maxlength:50,
        minlength:0,
        showPop:false,
        list:[],
        source: null
      }
    },
    created: function () {
      //是否隐藏行内label
      if(this.attributes.basis.hideLabel){
        this.labelInline=false;
      }
      //验证规则
      if (this.attributes.basis.validate) {
        if (this.attributes.basis.validate.isNumber == 1) {
          this.type = 'number';
        }
        if (this.attributes.basis.validate.express) {
          this.validFun = this.attributes.basis.validate.express;
        }
        if (this.attributes.basis.validate.max) {
          this.maxlength = +this.attributes.basis.validate.max;
        }
        if (this.attributes.basis.validate.min) {
          this.minlength = +this.attributes.basis.validate.min;
        }
      }
      //默认
      this.attributes.basis.defaultValue&&(this.attributes.value = this.attributes.basis.defaultValue.text);
      this.attributes.value==null&&(this.attributes.value="");

      // this.$set(this)
    },
    methods: {
      chooseItem(item){
        this.attributes.value = item.value;
        typeof window.$mobile_event.autocomplete_select === "function" && window.$mobile_event.autocomplete_select(this.$parent.commentID,item);
        let state = this.inputBlur();
        if(state !== false){
          this.showPop = false;
        }
      },
      changeV(v){
        let _this = this;
        if(this.source){
          clearTimeout(this.source);
        }
        if(v===""){
          _this.list = [];
        }else{
          this.source = setTimeout(()=>{
            if(this.attributes.basis.$source){
              this.$http.get(window.$mobile_page.requireHost?(window.$mobile_page.requireHost+'/dsfa/'):'dsfa/'+this.attributes.basis.$source, {
                params: {
                  q:v
                }
              }).then(result => {
                if (result.success) {
                    let arr = result.data.slice(0, parseInt(_this.attributes.basis.$maxItemsNumber));
                    let _arr = [];
                    for(let i in arr){
                      if(arr[i].value||typeof arr[i].value==='number'){
                        arr[i].lable = arr[i].lable || arr[i].value;
						            _arr.push(arr[i])
                      }
                    }
                    _this.list = _arr;
                }
              });
            }
          },400)
        }
      },
      inputFocus(e) {
        if(!this.attributes.basis.readOnly){
          window.$mobile_page.currentFocusInput=window.findClassParent(e.target,'form-item');
          this.showPop  = true;
          this.list = [];
        }else{
          return false
        }
        // this.top=window.pageYOffset
        //     || document.documentElement.scrollTop
        //     || document.body.scrollTop
        //     || 0;
      },
      inputBlur() {
        if(!this.attributes.basis.readOnly){
          // setTimeout(()=>{
          //   window.scrollTo(0, this.top);
          // },200);
          this.attributes.focus=false;
          if(!this.attributes['basis']['validate']&&this.attributes['basis']['validate']&&this.attributes['basis']['validate']['required']&&this.attributes.value===''){
            this.attributes.error=false;
            return false
          }
          if(this.attributes['basis']['validate']&&this.attributes['basis']['validate']&&this.attributes['basis']['validate']['required']&&!this.attributes.value){
            this.attributes.error=true;
            this.attributes.errorMsg = `请填写${this.attributes.basis.label}`;
            return false
          }
          if(this.attributes.value.length<this.minlength||this.attributes.value.length>this.maxlength){
            this.attributes.errorMsg = `填写长度在${this.minlength}到${this.maxlength}位`;
            this.attributes.error=true;
            this.$toast({
              duration:1500,
              message:this.attributes.errorMsg
            });
            return false
          }
          if(this.validFun){
            let ok = false;
            switch (this.validFun) {
              case 'isMobile':
                ok = this.isMobile();
                break;
              case 'isIDCard':
                ok = this.isIDCard();
                break;
              case 'isTelPhone':
                ok = this.isTelPhone();
                break;
              case 'isMobileOrTelPhone':
                ok = this.isMobileOrTelPhone();
                break;
              case 'isEmail':
                ok = this.isMobileOrTelPhone();
                break;
              case 'isPlateNumber':
                ok = this.isPlateNumber();
                break;
            }
            if(!ok){//验证未通过
              this.$toast({
                duration:1500,
                message:this.attributes.errorMsg
              });
              this.attributes.error=true;
              return false
            }else {}
          }
          if(this.type==='number'&&isNaN(this.attributes.value)){
            this.attributes.errorMsg = '只能输入数字';
            this.attributes.error=true;
            this.$toast({
              duration:1500,
              message:this.attributes.errorMsg
            });
            return false
          }
          this.attributes.error=false;
          this.emitParent(this.attributes.value);
        }else{
          return false
        }
      },
      isMobile() {
        if (!(/^1[3456789]\d{9}$/.test(this.attributes.value))) {
          this.attributes.errorMsg = "请填写正确的手机号码";
          return false
        }
        return true
      },
      //身份证
      isIDCard() {
        if (!(/(^\d{15}$)|(^\d{18}$)|(^\d{17}(\d|X|x)$)/.test(this.attributes.value))) {
          this.attributes.errorMsg = "请填写正确的身份证号码";
          return false
        }
        return true
      },
      isTelPhone() {
        if (!(/^(\(\d{3,4}\)|\d{3,4}-|\s)?\d{7,14}$/.test(this.attributes.value))) {
          this.attributes.errorMsg = "请填写正确的电话号码";
          return false
        }
        return true
      },
      isMobileOrTelPhone() {
        if (this.isMobile(this.attributes.value) || this.isTelPhone(this.attributes.value)) {
          return true
        }
        this.attributes.errorMsg = "请填写正确的联系方式";
        return false
      },
      isEmail() {
        if (!(/^([a-zA-Z]|[0-9])(\w|\-)+@[a-zA-Z0-9]+\.([a-zA-Z]{2,4})$/.test(this.attributes.value))) {
          this.attributes.errorMsg = "请填写正确的Email";
          return false
        }
        return true
      },
      //车牌号
      isPlateNumber() {
        var xreg = /^[京津沪渝冀豫云辽黑湘皖鲁新苏浙赣鄂桂甘晋蒙陕吉闽贵粤青藏川宁琼使领A-Z]{1}[A-Z]{1}(([0-9]{5}[DF]$)|([DF][A-HJ-NP-Z0-9][0-9]{4}$))/;
        var creg = /^[京津沪渝冀豫云辽黑湘皖鲁新苏浙赣鄂桂甘晋蒙陕吉闽贵粤青藏川宁琼使领A-Z]{1}[A-Z]{1}[A-HJ-NP-Z0-9]{4}[A-HJ-NP-Z0-9挂学警港澳]{1}$/;
        if (this.attributes.value.length == 7) {
          if (creg.test(this.attributes.value)) {
            return true
          }
        } else if (this.attributes.value.length == 8) {
          if (xreg.test(this.attributes.value)) {
            return true
          }
        } else {
          this.attributes.errorMsg = "请填写正确的车牌号";
          return false
        }
      },

    },
    components: {}
  }
</script>
