import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex);

const state = {
	title: '', //页面title
	forms: [], //表单集合
	subForm: {}, //表单答案
	questions: [], //问卷题库
	answers: {}, //问卷答案-E调查、小程序
	btnLoading: false, //提交按钮loading状态
	// numberKeyboard:false,//数字键盘
	showDialogInfo: false, //信息弹窗
	dialogInfoType: 'txt', //展示类型，txt,audio,video
	dialogInfoSource: '', //文本或url地址
	showTxtInfo: false, //试题信息弹窗
	showTxt: '暂无提示',
	examAnswer: {}, //正确答案
	examSaveData: {}, //保存过的数据
	examInfoData:{},//考试信息
};

const mutations = {
	setTitle(state, title) {
		document.title = title;
		state.title = title;
	},
	//表单
	initForms(state) {
		state.forms = [];
	},
	addForms(state, form) {
		state.forms.push(form);
	},
	initSub(state, sub) {
		state.subForm = sub;
	},
	setForms(state, answers) {
		for (let key in answers) {
			state.subForm[key] = answers[key];
		}
	},
	//问卷
	initQues(state) {
		state.questions = [];
	},
	addQues(state, question) {
		state.questions.push(question);
	},
	initAws(state, answer) {
		state.answers = answer;
	},
	setAws(state, answers) {
		for (let key in answers) {
			state.answers[key] = answers[key];
		}
	},
	//考试正确答案
	examAnswerInit(state,answer){
		state.examAnswer=answer;
	},
	//考试保存过的答案
	examSaveDataInit(state,save){
		state.examSaveData=save;
	},
	//考试信息
	examInfoInit(state,info){
		state.examInfoData=info;
	},
	examInfoChange(state,obj){
		for(let k in obj){
			state.examInfoData[k]=obj[k]
		}
	},
	changeExamPrompt(state, txt) {
		if (txt && typeof txt === 'string') {
			state.showTxt = txt;
			state.showTxtInfo = true;
		} else {
			state.showTxtInfo = false;
			state.showTxt = '暂无提示';
		}
	}
};

const actions = {
	// axiosAction(context){
	//   //axios resolve
	//   context.commit("setTitle",'测试');
	// }
};

const getters = {};

export default new Vuex.Store({
	state,
	actions,
	getters,
	mutations
})
