<template>
  <div class="van-font0 rank-btns">
    <van-button size="small" v-for="(btn,index) in btns" :key="index" @click="check(index)"
                :class="{'van-button--danger':selected==index}">{{btn.text}}
    </van-button>
  </div>
</template>

<script>
  import rank from './rank'

  export default {
    name: "ButtonRadio",
    mixins: [rank],
    props: {
      btns: {
        type: Array,
        default() {
          return []
        }
      }
    },
    data() {
      return {
        selected: -1,
      }
    },
    computed: {},
    components: {},
    created: function () {
      if (this.val || this.val === 0) {
        for (let i = 0, length = this.btns.length; i < length; i++) {
          if (this.btns[i]['value'] == (+this.val)) {
            this.check(i);
            return
          }
        }
      }
    },
    methods: {
      check(i) {
        this.selected = i;
        this.$emit('changeVal', this.btns[i], this.obj);
      }
    }
  }
</script>
