<template>
  <div id="app">
    <van-nav-bar
        v-if="$route.meta.showNav"
        :title="$store.state.title"
        right-text=""
        :left-text="showTopBar"
        :left-arrow="showTopBar?true:false"
        fixed
        :z-index="999"
        @click-left="back"
    >
    </van-nav-bar>
    <transition name="fade" mode="out-in">
      <!--开启分页之后需要缓存数据则启用keep-alive-->
      <!--<keep-alive>-->
      <router-view :key="key" :class="{'no-padding-top':!$route.meta.showNav}"/>
      <!--</keep-alive>-->
    </transition>
  </div>
</template>

<script>
  export default {
    name: 'app',
    data() {
      return {

      }
    },
    computed: {
      key() {
        return this.$route.path;
      },
      showTopBar() {
        return (this.$route.path != '/' && this.$route.path != '/index') ? '返回' : ''
      }
    },
    methods: {
      back() {
        this.$router.go(-1)
      }
    }
  }
</script>
