<template>
  <van-cell-group :title="label||'评价'" class="rank-div">
    <div class="total-rank van-padding">
      <van-icon name="star" color="#ff7200"/>
      <span class="total-span">总评分：{{score}}</span>
    </div>
    <div class="rank-box" v-for="(item,index) in attributes.rowSet.rows">
      <p class="rank-project van-padding">{{!!item.children?'项目组：':''}}{{item.project}}</p>
      <p v-if="attributes.rowSet.norm==1&&!item.children" class="rank-norm van-padding">评分标准：{{item.norm}}</p>
      <div v-if="item.children&&item.children.length>0">
        <div class="child-rank" v-for="(child,n) in item.children">
          <p class="rank-project van-padding">{{child.project}}</p>
          <p v-if="attributes.rowSet.norm==1" class="rank-norm van-padding">评分标准：{{child.norm}}</p>
          <div class="van-border"></div>
          <RankSelect v-if="attributes.styleType==1" :val="getVal(index,n)" @changeVal="valChange"
                      :obj="child"></RankSelect>
          <ButtonRadio v-else-if="attributes.styleType==4" :val="getVal(index,n)" @changeVal="valChange" :obj="child"
                       :btns="btns"></ButtonRadio>
          <div v-else></div>
        </div>
      </div>
      <div v-else>
        <div class="van-border"></div>
        <RankSelect v-if="attributes.styleType==1" @changeVal="valChange" :obj="item" :val="getVal(index)"></RankSelect>
        <ButtonRadio v-else-if="attributes.styleType==4" @changeVal="valChange" :obj="item" :val="getVal(index)"
                     :btns="btns"></ButtonRadio>
        <div v-else></div>
      </div>
    </div>
  </van-cell-group>
</template>

<script>
  import base from '../../../lib/base'
  import ButtonRadio from './ButtonRadio'
  import RankSelect from './RankSelect'

  export default {
    name: "Rank",
    extends: base,
    data() {
      return {
        score: 0,
        btns: [],
        chooseTypeData: [
          [
            {text: "1分", value: '1'},
            {text: "2分", value: '2'},
            {text: "3分", value: '3'},
            {text: "4分", value: '4'},
            {text: "5分", value: '5'}
          ],
          [
            {text: "1分", value: '1'},
            {text: "2分", value: '2'},
            {text: "3分", value: '3'},
            {text: "4分", value: '4'},
            {text: "5分", value: '5'},
            {text: "6分", value: '6'},
            {text: "7分", value: '7'},
            {text: "8分", value: '8'},
            {text: "9分", value: '9'},
            {text: "10分", value: '10'}
          ],
          [
            {text: '满意', value: '100'},
            {text: '不满意', value: '0'}
          ],
          [
            {text: '满意', value: '100'},
            {text: '基本满意', value: '50'},
            {text: '不满意', value: '0'}
          ],
          [
            {text: '很满意', value: '100'},
            {text: '满意', value: '66'},
            {text: '一般', value: '33'},
            {text: '不满意', value: '0'}
          ],
          [
            {text: '优秀', value: '100'},
            {text: '良好', value: '66'},
            {text: '一般', value: '33'},
            {text: '差', value: '0'}
          ]
        ]
      }
    },
    computed: {},
    components: {
      ButtonRadio, RankSelect
    },
    created: function () {
      if (this.attributes.styleType == 4) {
        this.btns = this.chooseTypeData[+this.attributes.chooseType - 1];
      }
      // this.attributes.basis.label = '评价';
    },
    methods: {
      getVal(index, n) {
        if (this.attributes.basis.defaultValue) {
          if (isNaN(n)) {
            if (isNaN(this.attributes.basis.defaultValue['pf_' + (index + 1)]) || this.attributes.basis.defaultValue['pf_' + (index + 1)] == null) {
              return ''
            } else {
              return this.attributes.basis.defaultValue['pf_' + (index + 1)]
            }
          } else {
            if (isNaN(this.attributes.basis.defaultValue['pf_' + (index + 1) + '_' + (n + 1)]) || this.attributes.basis.defaultValue['pf_' + (index + 1) + '_' + (n + 1)] == null) {
              return ''
            } else {
              return this.attributes.basis.defaultValue['pf_' + (index + 1) + '_' + (n + 1)]
            }
          }
        }
        return null
      },
      /**
       * 监听
       * @param val 选中的obj，{text,value}
       * @param obj 当前数据对象,level为1时obj===rows[index]===parent
       * 获取得分：根据index拿到父级数据对象，判断是否有二级
       * 有：判断是否有权重，是：得分=val*权重/100，否：val*(计算出的权重)/100
       * 无：同上，唯一不同点在于计算权重方法
       */
      valChange(val, obj) {
        //设置数据对象score为选中value
        obj.score = val.value;
        this.score = this.getTotal();
      },
      getTotal() {
        let total = 0;
        for (let i = 0, length = this.attributes.rowSet.rows.length; i < length; i++) {
          if (this.attributes.rowSet.rows[i]['children']) {
            let rowScore = 0;
            for (let n = 0, leng = this.attributes.rowSet.rows[i]['children'].length; n < leng; n++) {
              let score = this.getScore(this.attributes.rowSet.rows[i], this.attributes.rowSet.rows[i]['children'][n]['score'], this.attributes.rowSet.rows[i]['children'][n]);//当前选项得分
              rowScore += (+score);
            }
            this.attributes.rowSet.rows[i]['score'] = rowScore;
            total += (+rowScore);
          } else {
            let myScore = this.getScore(this.attributes.rowSet.rows[i], this.attributes.rowSet.rows[i]['score'], this.attributes.rowSet.rows[i]);//当前选项得分
            total += (+myScore);
          }
        }
        this.attributes.rowSet.total = total;
        let last = +total;
        return (last > 100 ? 100 : last).toFixed(2)
      },
      /**
       * 获取实际得分
       * @param parent 父级
       * @param val 得分
       * @param obj 当前数据对象
       * @returns {number}
       */
      getScore(parent, val, obj) {
        if (!val || isNaN(val)) {
          return 0
        }
        let weight = 0;
        //是否含有权重,0=否
        if (this.attributes.rowSet.weight == 0) {
          weight = +this.countWeight(parent);
        } else {
          weight = +this.getWeight(parent, obj);
        }
        return (+(+val * weight / 100)).toFixed(2)
      },
      //weight存在
      getWeight(parent, obj) {
        //是否为2级
        if (!!parent.children && parent.children.length > 0) {
          return obj.weight;
        } else {
          return parent.weight
        }
      },
      //weight不存在
      countWeight(parent) {
        let count = (+(100 / this.attributes.rowSet.rows.length)).toFixed(2);
        //是否为2级
        if (!!parent.children && parent.children.length > 0) {
          return (count / parent.children.length).toFixed(2)
        } else {
          return (+count).toFixed(2)
        }
      }
    }
  }
</script>
